// labels carry {uk,ru,en,de,it,es_ar,fr}; hints carry the six non-uk keys.
// Table cells hold ONLY Ukrainian forms.
const GRAMMAR = [
{"id":"alphabet-pronunciation","icon":"🔤","level":"A1","title":{"uk":"Абетка та вимова","ru":"Алфавит и произношение","en":"Alphabet & pronunciation","de":"Alphabet & Aussprache","it":"Alfabeto e pronuncia","es_ar":"الأبجدية والنطق","fr":"Alphabet et prononciation"},"intro":{"uk":"Українська абетка — 33 літери кирилиці. Пишемо як чуємо: майже кожна літера завжди звучить однаково. Особливі літери: Ґ ґ (тверде g), Г г (гортанне h), Є є (je), Ї ї (ji), И и (середнє між i та e), І і (i), апостроф ' розділяє приголосну та йотовану голосну.","ru":"Украинский алфавит — 33 буквы кириллицы. В отличие от русского нет ы, ё, ъ, э; зато есть ґ, є, і, ї, апостроф. Буква и читается как русское ы, а і — как русское и. Г — это фрикативное [h], а не [g].","en":"Ukrainian uses 33 Cyrillic letters and is highly phonetic — spell it as you hear it. Note и (like the 'i' in 'bit'), і (ee), ї (yee), є (ye), and Г which is a soft [h], not a hard [g] (that is Ґ).","de":"Das ukrainische Alphabet hat 33 kyrillische Buchstaben und ist weitgehend lautgetreu. Г klingt wie ein weiches [h] (wie in 'hallo'), nicht wie [g]; für [g] gibt es Ґ. и entspricht etwa dem kurzen deutschen i.","it":"L'alfabeto ucraino ha 33 lettere cirilliche ed è quasi perfettamente fonetico. Attenzione: Г si pronuncia [h] aspirata, non [g]; la [g] dura è Ґ. La и è una i centrale, la і è una i chiara.","es_ar":"الأبجدية الأوكرانية تتكوّن من 33 حرفًا سيريليًا وتُكتب كما تُلفظ تقريبًا. الحرف Г يُلفظ هاءً خفيفة [h] وليس [g]؛ أمّا [g] فيُكتب Ґ. والحرف и قريب من الكسرة القصيرة.","fr":"L'alphabet ukrainien compte 33 lettres cyrilliques et est presque parfaitement phonétique. Attention : Г se prononce [h] et non [g] (le [g] dur s'écrit Ґ) ; и est un i central, і un i clair."},"tables":[{"caption":{"uk":"Особливі літери та звуки","ru":"Особые буквы и звуки","en":"Special letters and sounds","de":"Besondere Buchstaben und Laute","it":"Lettere e suoni particolari","es_ar":"حروف وأصوات خاصة","fr":"Lettres et sons particuliers"},"labelHeader":{"uk":"Літера","ru":"Буква","en":"Letter","de":"Buchstabe","it":"Lettera","es_ar":"الحرف","fr":"Lettre"},"columns":[{"uk":"Приблизний звук","ru":"Примерный звук","en":"Approx. sound","de":"Ungefährer Laut","it":"Suono approssimativo","es_ar":"الصوت التقريبي","fr":"Son approximatif"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"Г г","ru":"Г г","en":"Г г","de":"Г г","it":"Г г","es_ar":"Г г","fr":"Г г"},"cells":["[h]","гора, нога"]},{"label":{"uk":"Ґ ґ","ru":"Ґ ґ","en":"Ґ ґ","de":"Ґ ґ","it":"Ґ ґ","es_ar":"Ґ ґ","fr":"Ґ ґ"},"cells":["[g]","ґудзик, ґанок"]},{"label":{"uk":"И и","ru":"И и","en":"И и","de":"И и","it":"И и","es_ar":"И и","fr":"И и"},"cells":["[ɪ]","риба, син"]},{"label":{"uk":"І і","ru":"І і","en":"І і","de":"І і","it":"І і","es_ar":"І і","fr":"І і"},"cells":["[i]","місто, ліс"]},{"label":{"uk":"Ї ї","ru":"Ї ї","en":"Ї ї","de":"Ї ї","it":"Ї ї","es_ar":"Ї ї","fr":"Ї ї"},"cells":["[ji]","їжа, Україна"]},{"label":{"uk":"Є є","ru":"Є є","en":"Є є","de":"Є є","it":"Є є","es_ar":"Є є","fr":"Є є"},"cells":["[je]","Європа, моє"]},{"label":{"uk":"апостроф '","ru":"апостроф '","en":"apostrophe '","de":"Apostroph '","it":"apostrofo '","es_ar":"الفاصلة العليا '","fr":"apostrophe '"},"cells":["[◦j]","м'ясо, п'ять"]}]}],"examples":[{"uk":"Добрий день! Мене звати Оля.","ru":"Добрый день! Меня зовут Оля.","en":"Good afternoon! My name is Olya.","de":"Guten Tag! Ich heiße Olja.","it":"Buongiorno! Mi chiamo Olja.","es_ar":"مساء الخير! اسمي أوليا.","fr":"Bonjour ! Je m'appelle Olia."},{"uk":"Ґудзик і гудзик — чуєте різницю між Ґ і Г?","ru":"Ґудзик и гудзик — слышите разницу между Ґ и Г?","en":"Ґudzyk and hudzyk — can you hear the difference between Ґ and Г?","de":"Ґudzyk und hudzyk — hören Sie den Unterschied zwischen Ґ und Г?","it":"Ґudzyk e hudzyk — senti la differenza tra Ґ e Г?","es_ar":"Ґудзик وгудзик — هل تسمع الفرق بين Ґ وГ؟","fr":"Ґoudzyk et houdzyk — entendez-vous la différence entre Ґ et Г ?"}],"hints":{"ru":"Не читайте г как [g]! В украинском это [h]: «гарний» звучит как «harnyj». Буквы ы в украинском нет — вместо неё и. И не путайте и (≈русское ы) с і (≈русское и).","en":"Don't read Ukrainian и as English 'ee' — it is the lax [ɪ] of 'sit'. The clear 'ee' is і. Ukrainian has no silent letters; even о is always full, never a schwa.","de":"Verwechseln Sie и nicht mit і: и ist ein kurzes, offenes [ɪ], і ein klares [i]. Und Г ist [h], nicht [g] — 'дякую' spricht man 'djakuju' mit weichem h.","it":"Non leggere Г come [g]: è sempre [h]. Distingui и (i centrale, tipo 'ы' russo) da і (i chiara). Ogni vocale va pronunciata piena, mai come una vocale indistinta.","es_ar":"لا تلفظ الحرف Г كـ [g]؛ فهو دائمًا [h]. ميّز بين и (كسرة مركزية) و і (كسرة صافية). تُلفظ كل حروف العلة كاملةً دون اختزال.","fr":"Ne prononcez pas Г comme [g] : c'est toujours [h]. Distinguez и (i central) de і (i clair). Toutes les voyelles se prononcent pleinement, jamais comme un e muet."}},
{"id":"noun-gender","icon":"⚥","level":"A1","title":{"uk":"Рід іменників","ru":"Род существительных","en":"Noun gender","de":"Genus der Substantive","it":"Genere dei nomi","es_ar":"جنس الأسماء","fr":"Genre des noms"},"intro":{"uk":"Іменники бувають чоловічого, жіночого або середнього роду. Найчастіше рід видно із закінчення в називному відмінку: приголосна — чоловічий (стіл, брат), -а/-я — жіночий (мама, земля), -о/-е/-я — середній (вікно, море, ім'я). Слова на -ь можуть бути як чоловічого (день), так і жіночого (ніч).","ru":"Как и в русском, три рода. Правила похожи, но не совпадают: украинское слово может отличаться родом от русского. Напр. «біль», «степ», «Сибір», «собака» в украинском мужского рода, «путь» — женского. Всегда проверяйте род отдельно.","en":"Ukrainian nouns are masculine, feminine, or neuter. Gender is usually shown by the ending: a consonant = masculine (стіл), -а/-я = feminine (мама), -о/-е/-я = neuter (вікно). Nouns in -ь can be either gender, so learn them individually.","de":"Ukrainische Substantive sind maskulin, feminin oder neutrum. Das Genus zeigt meist die Endung: Konsonant = maskulin, -а/-я = feminin, -о/-е = neutrum. Achtung: es gibt kein 'der/die/das' — das Genus steckt allein in der Endung.","it":"I nomi ucraini sono maschili, femminili o neutri. Il genere si vede dalla desinenza: consonante = maschile, -а/-я = femminile, -о/-е = neutro. Non esiste l'articolo, quindi il genere si ricava solo dalla forma della parola.","es_ar":"الأسماء الأوكرانية مذكّرة أو مؤنّثة أو محايدة. يُعرف الجنس غالبًا من النهاية: حرف ساكن = مذكّر، -а/-я = مؤنّث، -о/-е = محايد. لا توجد أداة تعريف، فالجنس يظهر من شكل الكلمة فقط.","fr":"Les noms ukrainiens sont masculins, féminins ou neutres. Le genre se lit dans la terminaison : consonne = masculin, -а/-я = féminin, -о/-е = neutre. Il n'y a pas d'article ; le genre se déduit uniquement de la forme du mot."},"tables":[{"caption":{"uk":"Типові закінчення за родом (називний відмінок)","ru":"Типичные окончания по роду (именительный падеж)","en":"Typical endings by gender (nominative)","de":"Typische Endungen nach Genus (Nominativ)","it":"Desinenze tipiche per genere (nominativo)","es_ar":"النهايات النمطية حسب الجنس (حالة الرفع)","fr":"Terminaisons typiques par genre (nominatif)"},"labelHeader":{"uk":"Рід","ru":"Род","en":"Gender","de":"Genus","it":"Genere","es_ar":"الجنس","fr":"Genre"},"columns":[{"uk":"Закінчення","ru":"Окончание","en":"Ending","de":"Endung","it":"Desinenza","es_ar":"النهاية","fr":"Terminaison"},{"uk":"Приклади","ru":"Примеры","en":"Examples","de":"Beispiele","it":"Esempi","es_ar":"أمثلة","fr":"Exemples"}],"rows":[{"label":{"uk":"чоловічий","ru":"мужской","en":"masculine","de":"maskulin","it":"maschile","es_ar":"مذكّر","fr":"masculin"},"cells":["приголосна, -й","стіл, брат, чай, край"]},{"label":{"uk":"жіночий","ru":"женский","en":"feminine","de":"feminin","it":"femminile","es_ar":"مؤنّث","fr":"féminin"},"cells":["-а, -я","мама, земля, книга"]},{"label":{"uk":"середній","ru":"средний","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["-о, -е, -я","вікно, море, ім'я, теля"]},{"label":{"uk":"на -ь (обидва)","ru":"на -ь (оба)","en":"in -ь (either)","de":"auf -ь (beide)","it":"in -ь (entrambi)","es_ar":"على -ь (كلاهما)","fr":"en -ь (les deux)"},"cells":["день (ч.р.), ніч (ж.р.)","учитель, сіль, любов"]}]}],"examples":[{"uk":"Це великий стіл. (чоловічий рід)","ru":"Это большой стол. (мужской род)","en":"This is a big table. (masculine)","de":"Das ist ein großer Tisch. (maskulin)","it":"Questo è un grande tavolo. (maschile)","es_ar":"هذه طاولة كبيرة. (مذكّر)","fr":"C'est une grande table. (masculin)"},{"uk":"Моя мама читає книгу. (жіночий рід)","ru":"Моя мама читает книгу. (женский род)","en":"My mum is reading a book. (feminine)","de":"Meine Mutter liest ein Buch. (feminin)","it":"Mia mamma legge un libro. (femminile)","es_ar":"أمّي تقرأ كتابًا. (مؤنّث)","fr":"Ma maman lit un livre. (féminin)"},{"uk":"Вікно відчинене. (середній рід)","ru":"Окно открыто. (средний род)","en":"The window is open. (neuter)","de":"Das Fenster ist offen. (neutrum)","it":"La finestra è aperta. (neutro)","es_ar":"النافذة مفتوحة. (محايد)","fr":"La fenêtre est ouverte. (neutre)"}],"hints":{"ru":"Не переносите род автоматически из русского! «Собака», «біль», «степ», «Сибір» — в украинском мужского рода, «путь» — женского. Слова на -ь запоминайте с родом: день (м.), ніч (ж.).","en":"Gender drives every adjective and verb ending, so learn each noun with its gender. Nouns in -ь are unpredictable (день is masc., ніч is fem.) — memorise them one by one.","de":"Da es keinen Artikel gibt, müssen Sie das Genus mitlernen — es bestimmt alle Adjektiv- und Verbendungen. Wörter auf -ь sind unvorhersehbar: день (m.) vs. ніч (f.).","it":"Senza articolo, il genere va imparato con ogni nome perché regola tutte le desinenze. I nomi in -ь sono imprevedibili: день (m.) contro ніч (f.).","es_ar":"بما أنه لا توجد أداة تعريف، احفظ الجنس مع كل اسم لأنه يتحكّم بكل النهايات. الأسماء المنتهية بـ -ь غير منتظمة: день (مذكّر) مقابل ніч (مؤنّث).","fr":"Sans article, apprenez le genre avec chaque nom : il commande toutes les terminaisons. Les noms en -ь sont imprévisibles : день (m.) contre ніч (f.)."}},
{"id":"plural-nouns","icon":"🔢","level":"A1","title":{"uk":"Множина іменників","ru":"Множественное число существительных","en":"Plural of nouns","de":"Plural der Substantive","it":"Plurale dei nomi","es_ar":"جمع الأسماء","fr":"Pluriel des noms"},"intro":{"uk":"Більшість іменників у множині мають закінчення -и, -і або -а. Тверді основи беруть -и (стіл → столи), м'які та після г/к/х — -і (кінь → коні, книга → книги), середній рід часто -а (вікно → вікна, море → моря). Увага на чергування приголосних: рук-а → рук-и, ног-а → ног-и, друг → друзі.","ru":"Как и в русском, есть множественное число, но окончания другие: чаще -и/-і, а не -ы/-и. При образовании множины работают чередования г/ж/з, к/ч/ц, х/ш/с и иногда о/е → і исчезает: стіл → столи, ніч → ночі, друг → друзі.","en":"Most Ukrainian plurals end in -и, -і, or -а. Hard stems take -и (стіл → столи); soft stems and stems in г/к/х take -і (кінь → коні); many neuters take -а (вікно → вікна). Watch for consonant shifts: друг → друзі.","de":"Die meisten Plurale enden auf -и, -і oder -а. Harte Stämme: -и (стіл → столи); weiche Stämme und г/к/х: -і (кінь → коні); viele Neutra: -а (вікно → вікна). Achten Sie auf Konsonantenwechsel: друг → друзі.","it":"La maggior parte dei plurali finisce in -и, -і o -а. Temi duri: -и (стіл → столи); temi molli e in г/к/х: -і (кінь → коні); molti neutri: -а (вікно → вікна). Attenzione alle alternanze: друг → друзі.","es_ar":"معظم صيغ الجمع تنتهي بـ -и أو -і أو -а. الجذور الصلبة: -и (стіл → столи)؛ الجذور اللينة وг/к/х: -і (кінь → коні)؛ كثير من المحايد: -а (вікно → вікна). انتبه للتبادلات: друг → друзі.","fr":"La plupart des pluriels se terminent en -и, -і ou -а. Radicaux durs : -и (стіл → столи) ; radicaux mous et en г/к/х : -і (кінь → коні) ; beaucoup de neutres : -а (вікно → вікна). Attention aux alternances : друг → друзі."},"tables":[{"caption":{"uk":"Однина → множина","ru":"Единственное → множественное","en":"Singular → plural","de":"Singular → Plural","it":"Singolare → plurale","es_ar":"المفرد ← الجمع","fr":"Singulier → pluriel"},"labelHeader":{"uk":"Тип","ru":"Тип","en":"Type","de":"Typ","it":"Tipo","es_ar":"النوع","fr":"Type"},"columns":[{"uk":"Однина","ru":"Ед. число","en":"Singular","de":"Singular","it":"Singolare","es_ar":"المفرد","fr":"Singulier"},{"uk":"Множина","ru":"Мн. число","en":"Plural","de":"Plural","it":"Plurale","es_ar":"الجمع","fr":"Pluriel"}],"rows":[{"label":{"uk":"тверда основа (ч.р.)","ru":"твёрдая основа (м.р.)","en":"hard masc.","de":"harter Stamm (m.)","it":"tema duro (m.)","es_ar":"جذر صلب (مذكّر)","fr":"radical dur (m.)"},"cells":["стіл, брат","столи, брати"]},{"label":{"uk":"м'яка основа","ru":"мягкая основа","en":"soft stem","de":"weicher Stamm","it":"tema molle","es_ar":"جذر لين","fr":"radical mou"},"cells":["кінь, учитель","коні, учителі"]},{"label":{"uk":"жіночий на -а/-я","ru":"женский на -а/-я","en":"fem. -а/-я","de":"fem. -а/-я","it":"femm. -а/-я","es_ar":"مؤنّث -а/-я","fr":"fém. -а/-я"},"cells":["книга, земля","книги, землі"]},{"label":{"uk":"середній на -о/-е","ru":"средний на -о/-е","en":"neuter -о/-е","de":"neutrum -о/-е","it":"neutro -о/-е","es_ar":"محايد -о/-е","fr":"neutre -о/-е"},"cells":["вікно, море","вікна, моря"]},{"label":{"uk":"з чергуванням","ru":"с чередованием","en":"with alternation","de":"mit Wechsel","it":"con alternanza","es_ar":"مع تبادل","fr":"avec alternance"},"cells":["друг, рука, нога","друзі, руки, ноги"]},{"label":{"uk":"нерегулярні","ru":"нерегулярные","en":"irregular","de":"unregelmäßig","it":"irregolari","es_ar":"شاذّة","fr":"irréguliers"},"cells":["людина, дитина","люди, діти"]}]}],"examples":[{"uk":"На вулиці стоять нові будинки.","ru":"На улице стоят новые дома.","en":"There are new buildings on the street.","de":"Auf der Straße stehen neue Häuser.","it":"In strada ci sono nuovi edifici.","es_ar":"توجد مبانٍ جديدة في الشارع.","fr":"Il y a de nouveaux immeubles dans la rue."},{"uk":"Мої друзі люблять книги.","ru":"Мои друзья любят книги.","en":"My friends love books.","de":"Meine Freunde lieben Bücher.","it":"I miei amici amano i libri.","es_ar":"أصدقائي يحبّون الكتب.","fr":"Mes amis aiment les livres."},{"uk":"У парку граються діти.","ru":"В парке играют дети.","en":"Children are playing in the park.","de":"Im Park spielen Kinder.","it":"Nel parco giocano i bambini.","es_ar":"الأطفال يلعبون في الحديقة.","fr":"Des enfants jouent dans le parc."}],"hints":{"ru":"Помните о чередованиях: друг → друзі, вухо → вуха, око → очі. И нерегулярные: людина → люди, дитина → діти, курча → курчата. Окончание -і в украинском там, где русский даёт -и (столы → столи с -и, но ночі, коні с -і).","en":"Don't just add -s: the whole ending changes, and stems can shift (друг → друзі, око → очі). A few plurals are suppletive: людина → люди, дитина → діти. Choose -и vs -і by whether the stem is hard or soft.","de":"Nicht einfach -s anhängen: die Endung ändert sich ganz, oft mit Stammwechsel (друг → друзі). Einige Plurale sind unregelmäßig: людина → люди, дитина → діти. -и nach hartem, -і nach weichem Stamm.","it":"Non aggiungere una -s: cambia tutta la desinenza e a volte il tema (друг → друзі). Alcuni plurali sono suppletivi: людина → люди, дитина → діти. Usa -и dopo tema duro, -і dopo tema molle.","es_ar":"لا تضِف حرف جمع بسيطًا: تتغيّر النهاية كاملةً وقد يتغيّر الجذر (друг → друзі). بعض الجموع شاذّة: людина → люди، дитина → діти. استعمل -и بعد الجذر الصلب و-і بعد اللين.","fr":"N'ajoutez pas un simple -s : toute la terminaison change, parfois avec le radical (друг → друзі). Certains pluriels sont irréguliers : людина → люди, дитина → діти. -и après radical dur, -і après radical mou."}},
{"id":"personal-pronouns","icon":"🙋","level":"A1","title":{"uk":"Особові займенники","ru":"Личные местоимения","en":"Personal pronouns","de":"Personalpronomen","it":"Pronomi personali","es_ar":"الضمائر الشخصية","fr":"Pronoms personnels"},"intro":{"uk":"Особові займенники: я, ти, він, вона, воно, ми, ви, вони. «Ви» — це і множина, і ввічлива форма звертання до однієї особи (з великої літери на письмі: Ви). Займенник не обов'язковий, бо особу видно із закінчення дієслова, але вживається для наголосу.","ru":"Местоимения: я, ти, він, вона, воно, ми, ви, вони. Обратите внимание: «ти» пишется через и, а не через ы. Вежливое «Ви» — как русское «Вы». Он/она/оно = він/вона/воно.","en":"The pronouns are я, ти, він, вона, воно, ми, ви, вони. Ви is both the plural 'you' and the polite singular 'you' (capitalised as Ви when addressing one person). Because verb endings show the person, the pronoun is often optional.","de":"Die Pronomen sind я, ти, він, вона, воно, ми, ви, вони. Ви ist sowohl das Plural-'ihr' als auch das höfliche Sie (großgeschrieben als Ви). Da die Verbendung die Person zeigt, kann das Pronomen oft entfallen.","it":"I pronomi sono я, ти, він, вона, воно, ми, ви, вони. Ви è sia il 'voi' plurale sia il 'Lei' di cortesia (scritto Ви). Poiché la desinenza del verbo indica la persona, il pronome è spesso facoltativo.","es_ar":"الضمائر هي я، ти، він، вона، воно، ми، ви، вони. والضمير Ви يعني «أنتم» للجمع و«حضرتك» للتأدّب (يُكتب بحرف كبير Ви). وبما أنّ نهاية الفعل تُظهر الشخص، فغالبًا ما يكون الضمير اختياريًا.","fr":"Les pronoms sont я, ти, він, вона, воно, ми, ви, вони. Ви est à la fois le « vous » pluriel et le « vous » de politesse (écrit Ви). Comme la terminaison du verbe indique la personne, le pronom est souvent facultatif."},"tables":[{"caption":{"uk":"Особові займенники (називний відмінок)","ru":"Личные местоимения (именительный падеж)","en":"Personal pronouns (nominative)","de":"Personalpronomen (Nominativ)","it":"Pronomi personali (nominativo)","es_ar":"الضمائر الشخصية (حالة الرفع)","fr":"Pronoms personnels (nominatif)"},"labelHeader":{"uk":"Особа","ru":"Лицо","en":"Person","de":"Person","it":"Persona","es_ar":"الشخص","fr":"Personne"},"columns":[{"uk":"Однина","ru":"Единственное","en":"Singular","de":"Singular","it":"Singolare","es_ar":"المفرد","fr":"Singulier"},{"uk":"Множина","ru":"Множественное","en":"Plural","de":"Plural","it":"Plurale","es_ar":"الجمع","fr":"Pluriel"}],"rows":[{"label":{"uk":"1-ша","ru":"1-е","en":"1st","de":"1.","it":"1ª","es_ar":"الأول","fr":"1re"},"cells":["я","ми"]},{"label":{"uk":"2-га","ru":"2-е","en":"2nd","de":"2.","it":"2ª","es_ar":"الثاني","fr":"2e"},"cells":["ти","ви / Ви"]},{"label":{"uk":"3-тя","ru":"3-е","en":"3rd","de":"3.","it":"3ª","es_ar":"الثالث","fr":"3e"},"cells":["він, вона, воно","вони"]}]}],"examples":[{"uk":"Я студент, а ти лікар.","ru":"Я студент, а ты врач.","en":"I am a student, and you are a doctor.","de":"Ich bin Student, und du bist Arzt.","it":"Io sono studente e tu sei medico.","es_ar":"أنا طالب وأنتَ طبيب.","fr":"Je suis étudiant et toi tu es médecin."},{"uk":"Вибачте, Ви не знаєте, де вокзал?","ru":"Извините, Вы не знаете, где вокзал?","en":"Excuse me, do you (polite) know where the station is?","de":"Entschuldigung, wissen Sie, wo der Bahnhof ist?","it":"Scusi, Lei sa dov'è la stazione?","es_ar":"عذرًا، هل تعرف حضرتك أين المحطة؟","fr":"Excusez-moi, savez-vous où est la gare ?"},{"uk":"Вони живуть у Києві.","ru":"Они живут в Киеве.","en":"They live in Kyiv.","de":"Sie wohnen in Kyjiw.","it":"Loro vivono a Kyiv.","es_ar":"هم يعيشون في كييف.","fr":"Ils habitent à Kyiv."}],"hints":{"ru":"«Ти» пишется через и (не «ты»!). Различайте ти (неформально, к близким) и Ви (вежливо/множ.). Он/оно — він/воно (не «он»), она — вона. Опускать местоимение можно, как в русском.","en":"Use ти for friends, family and children; use Ви for strangers and formal situations — mixing them up sounds rude or oddly distant. English has one 'you', so make this distinction consciously.","de":"ти ist wie 'du', Ви wie 'Sie'/'ihr'. Anders als im Deutschen ist Ви auch der Höflichkeitsplural. Das falsche Register (du statt Sie) wirkt unhöflich — wählen Sie bewusst.","it":"ти è il 'tu', Ви il 'Lei'/'voi'. A differenza dell'italiano, Ви serve sia per il plurale sia per la cortesia. Sbagliare registro (dare del tu) suona scortese.","es_ar":"الضمير ти للأصدقاء والعائلة، وВи للغرباء والمواقف الرسمية (وللجمع أيضًا). الخلط بينهما قد يبدو وقاحةً، فاختر بوعي.","fr":"ти correspond au tutoiement, Ви au vouvoiement (et au pluriel). Comme en français, employer « tu » à la place de « vous » peut paraître impoli — choisissez le registre consciemment."}},
{"id":"present-tense","icon":"🔄","level":"A1","title":{"uk":"Теперішній час (дієвідміни I і II)","ru":"Настоящее время (I и II спряжения)","en":"Present tense (conjugations I & II)","de":"Präsens (Konjugationen I & II)","it":"Presente (coniugazioni I e II)","es_ar":"المضارع (التصريفان الأول والثاني)","fr":"Présent (conjugaisons I et II)"},"intro":{"uk":"Дієслова в теперішньому часі мають дві дієвідміни. I дієвідміна має в закінченнях голосну -е- (читати → читаєш, читає), II — голосну -и-/-ї- (говорити → говориш, говорить). Особу і число показує закінчення, тому займенник часто пропускають.","ru":"Два спряжения, как и в русском. I спряжение — с гласной -е- (читаєш, читає), II — с -и-/-ї- (говориш, говорить). Внимание: во 2 л. ед.ч. окончание -еш/-иш (не -ешь/-ишь — мягкого знака нет!). В 3 л. мн.ч. I спр. -уть/-ють, II спр. -ать/-ять.","en":"Ukrainian verbs fall into two conjugations. Type I has the vowel -е- in its endings (читаєш, читає); type II has -и-/-ї- (говориш, говорить). The ending marks person and number, so the pronoun is often dropped.","de":"Verben gehören zu zwei Konjugationen. Typ I hat den Vokal -е- (читаєш, читає), Typ II den Vokal -и-/-ї- (говориш, говорить). Die Endung zeigt Person und Zahl, daher entfällt das Pronomen oft.","it":"I verbi hanno due coniugazioni. Il tipo I ha la vocale -е- (читаєш, читає); il tipo II ha -и-/-ї- (говориш, говорить). La desinenza indica persona e numero, quindi il pronome spesso si omette.","es_ar":"الأفعال لها تصريفان. التصريف الأول فيه حرف العلة -е- (читаєш، читає)؛ والثاني فيه -и-/-ї- (говориш، говорить). النهاية تُظهر الشخص والعدد، لذا يُحذف الضمير غالبًا.","fr":"Les verbes se répartissent en deux conjugaisons. Le type I a la voyelle -е- (читаєш, читає) ; le type II a -и-/-ї- (говориш, говорить). La terminaison marque la personne et le nombre, d'où l'omission fréquente du pronom."},"tables":[{"caption":{"uk":"читати (I) і говорити (II) — теперішній час","ru":"читати (I) и говорити (II) — настоящее время","en":"читати (I) & говорити (II) — present","de":"читати (I) & говорити (II) — Präsens","it":"читати (I) e говорити (II) — presente","es_ar":"читати (الأول) وговорити (الثاني) — المضارع","fr":"читати (I) et говорити (II) — présent"},"labelHeader":{"uk":"Займенник","ru":"Местоимение","en":"Pronoun","de":"Pronomen","it":"Pronome","es_ar":"الضمير","fr":"Pronom"},"columns":[{"uk":"читати (I)","ru":"читати (I)","en":"читати (I)","de":"читати (I)","it":"читати (I)","es_ar":"читати (الأول)","fr":"читати (I)"},{"uk":"говорити (II)","ru":"говорити (II)","en":"говорити (II)","de":"говорити (II)","it":"говорити (II)","es_ar":"говорити (الثاني)","fr":"говорити (II)"}],"rows":[{"label":{"uk":"я","ru":"я","en":"я","de":"я","it":"я","es_ar":"я","fr":"я"},"cells":["читаю","говорю"]},{"label":{"uk":"ти","ru":"ти","en":"ти","de":"ти","it":"ти","es_ar":"ти","fr":"ти"},"cells":["читаєш","говориш"]},{"label":{"uk":"він/вона/воно","ru":"він/вона/воно","en":"він/вона/воно","de":"він/вона/воно","it":"він/вона/воно","es_ar":"він/вона/воно","fr":"він/вона/воно"},"cells":["читає","говорить"]},{"label":{"uk":"ми","ru":"ми","en":"ми","de":"ми","it":"ми","es_ar":"ми","fr":"ми"},"cells":["читаємо","говоримо"]},{"label":{"uk":"ви","ru":"ви","en":"ви","de":"ви","it":"ви","es_ar":"ви","fr":"ви"},"cells":["читаєте","говорите"]},{"label":{"uk":"вони","ru":"вони","en":"вони","de":"вони","it":"вони","es_ar":"вони","fr":"вони"},"cells":["читають","говорять"]}]}],"examples":[{"uk":"Я читаю газету щоранку.","ru":"Я читаю газету каждое утро.","en":"I read the newspaper every morning.","de":"Ich lese jeden Morgen die Zeitung.","it":"Leggo il giornale ogni mattina.","es_ar":"أقرأ الجريدة كل صباح.","fr":"Je lis le journal chaque matin."},{"uk":"Ти говориш українською?","ru":"Ты говоришь по-украински?","en":"Do you speak Ukrainian?","de":"Sprichst du Ukrainisch?","it":"Parli ucraino?","es_ar":"هل تتكلّم الأوكرانية؟","fr":"Parles-tu ukrainien ?"},{"uk":"Ми живемо і працюємо в Києві.","ru":"Мы живём и работаем в Киеве.","en":"We live and work in Kyiv.","de":"Wir leben und arbeiten in Kyjiw.","it":"Viviamo e lavoriamo a Kyiv.","es_ar":"نعيش ونعمل في كييف.","fr":"Nous vivons et travaillons à Kyiv."}],"hints":{"ru":"Не пишите мягкий знак в -еш/-иш (укр. читаєш, а не «читаєшь»). 3 л. ед. II спр. оканчивается на -ить/-ать/-ять с -ть на конце (говорить), а не на -ит. В 1 л. ед. часто чередование: ходити → ходжу, любити → люблю.","en":"Learn a verb's type from its 3rd-person forms: -е-/-є- means type I, -и-/-ї- means type II. The 1st-person singular often shows a consonant shift: ходити → ходжу, любити → люблю. There is no auxiliary 'do' — just conjugate.","de":"Erkennen Sie die Konjugation an der 3. Person: -е-/-є- = Typ I, -и-/-ї- = Typ II. Die 1. Person Singular zeigt oft einen Konsonantenwechsel: ходити → ходжу. Es gibt keine Umschreibung — einfach konjugieren.","it":"Riconosci la coniugazione dalla 3ª persona: -е-/-є- = tipo I, -и-/-ї- = tipo II. La 1ª persona singolare mostra spesso un'alternanza: ходити → ходжу, любити → люблю. Non esiste ausiliare: si coniuga direttamente.","es_ar":"اعرف التصريف من صيغة الغائب: -е-/-є- = الأول، -и-/-ї- = الثاني. وصيغة المتكلّم المفرد كثيرًا ما تُظهر تبادلًا: ходити → ходжу. لا يوجد فعل مساعد؛ يُصرَّف الفعل مباشرةً.","fr":"Reconnaissez la conjugaison à la 3e personne : -е-/-є- = type I, -и-/-ї- = type II. La 1re personne du singulier montre souvent une alternance : ходити → ходжу, любити → люблю. Pas d'auxiliaire : on conjugue directement."}},
{"id":"verb-buty-copula","icon":"🟰","level":"A1","title":{"uk":"Дієслово «бути» та відсутність зв'язки","ru":"Глагол «бути» и отсутствие связки","en":"The verb 'бути' & the missing copula","de":"Das Verb 'бути' & die fehlende Kopula","it":"Il verbo 'бути' e la copula assente","es_ar":"الفعل «бути» وغياب رابطة الإسناد","fr":"Le verbe 'бути' et la copule absente"},"intro":{"uk":"У теперішньому часі дієслово «бути» (=бути кимось/чимось) зазвичай не вживається: «Я студент», «Вона лікарка». Форма «є» вживається для наголосу, у значенні «існує/мається», а також в конструкціях «у мене є». Минулий і майбутній час бути повноцінний: був/була/було/були; буду, будеш…","ru":"В настоящем времени связка обычно опускается, как и в русском: «Я студент», «Вона вчителька» — без «есть». Форма «є» = русское «есть» (существует / имеется): «У мене є брат». В прошедшем и будущем «бути» ставится полностью: був/була; буду, будеш.","en":"In the present tense the verb 'to be' is normally dropped: «Я студент» = 'I am a student' (no verb). The form «є» means 'there is / exists' and appears in «у мене є» (I have). In the past and future, бути is fully used: був/була, буду.","de":"Im Präsens fehlt die Kopula 'sein': «Я студент» = 'Ich bin Student' (ohne Verb). Die Form «є» heißt 'es gibt / existiert' und steht in «у мене є» (ich habe). In Vergangenheit und Zukunft steht бути voll: був/була, буду.","it":"Al presente la copula 'essere' di norma si omette: «Я студент» = 'Sono studente' (senza verbo). La forma «є» significa 'c'è / esiste' e compare in «у мене є» (ho). Al passato e al futuro бути si usa per intero: був/була, буду.","es_ar":"في المضارع تُحذف عادةً رابطة «يكون»: «Я студент» أي «أنا طالب» (بلا فعل). أمّا الصيغة «є» فتعني «يوجد» وتظهر في «у мене є» (لديّ). وفي الماضي والمستقبل يُستعمل بути كاملًا: був/була، буду.","fr":"Au présent, la copule « être » est normalement omise : «Я студент» = « je suis étudiant » (sans verbe). La forme «є» signifie « il y a / existe » et apparaît dans «у мене є» (j'ai). Au passé et au futur, бути est employé pleinement : був/була, буду."},"tables":[{"caption":{"uk":"«бути»: минулий, теперішній, майбутній","ru":"«бути»: прошедшее, настоящее, будущее","en":"«бути»: past, present, future","de":"«бути»: Vergangenheit, Präsens, Zukunft","it":"«бути»: passato, presente, futuro","es_ar":"«бути»: الماضي والمضارع والمستقبل","fr":"«бути» : passé, présent, futur"},"labelHeader":{"uk":"Час / особа","ru":"Время / лицо","en":"Tense / person","de":"Zeit / Person","it":"Tempo / persona","es_ar":"الزمن / الشخص","fr":"Temps / personne"},"columns":[{"uk":"Форма","ru":"Форма","en":"Form","de":"Form","it":"Forma","es_ar":"الصيغة","fr":"Forme"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"теперішній (усі особи)","ru":"настоящее (все лица)","en":"present (all persons)","de":"Präsens (alle)","it":"presente (tutte)","es_ar":"المضارع (كل الأشخاص)","fr":"présent (toutes)"},"cells":["— (є)","Я лікар. / У мене є час."]},{"label":{"uk":"минулий ч.р.","ru":"прошедшее м.р.","en":"past masc.","de":"Vergangenheit m.","it":"passato m.","es_ar":"الماضي مذكّر","fr":"passé m."},"cells":["був","Він був удома."]},{"label":{"uk":"минулий ж.р.","ru":"прошедшее ж.р.","en":"past fem.","de":"Vergangenheit f.","it":"passato f.","es_ar":"الماضي مؤنّث","fr":"passé f."},"cells":["була","Вона була рада."]},{"label":{"uk":"минулий с.р. / мн.","ru":"прошедшее ср.р. / мн.","en":"past neut. / plur.","de":"Vergangenheit n./Pl.","it":"passato n./pl.","es_ar":"الماضي محايد/جمع","fr":"passé n./pl."},"cells":["було / були","Було пізно. Ми були там."]},{"label":{"uk":"майбутній","ru":"будущее","en":"future","de":"Zukunft","it":"futuro","es_ar":"المستقبل","fr":"futur"},"cells":["буду, будеш, буде, будемо, будете, будуть","Завтра я буду вдома."]}]}],"examples":[{"uk":"Я вчитель, а вона — лікарка.","ru":"Я учитель, а она — врач.","en":"I am a teacher, and she is a doctor.","de":"Ich bin Lehrer, und sie ist Ärztin.","it":"Io sono insegnante e lei è medico.","es_ar":"أنا معلّم وهي طبيبة.","fr":"Je suis enseignant et elle est médecin."},{"uk":"У мене є два брати.","ru":"У меня есть два брата.","en":"I have two brothers.","de":"Ich habe zwei Brüder.","it":"Ho due fratelli.","es_ar":"لديّ أخوان.","fr":"J'ai deux frères."},{"uk":"Учора я був на роботі, а завтра буду вдома.","ru":"Вчера я был на работе, а завтра буду дома.","en":"Yesterday I was at work, and tomorrow I'll be at home.","de":"Gestern war ich auf der Arbeit, und morgen bin ich zu Hause.","it":"Ieri ero al lavoro e domani sarò a casa.","es_ar":"أمس كنت في العمل، وغدًا سأكون في البيت.","fr":"Hier j'étais au travail et demain je serai à la maison."}],"hints":{"ru":"Не добавляйте глагол в настоящем: «Я студент», а не «Я є студент». «Є» ставьте только в значении «есть/имеется» (у мене є). В прошедшем не забудьте согласовать род: він був, вона була, воно було, вони були.","en":"Don't insert 'am/is/are' in the present — «Я студент» already means 'I am a student'. Use «є» only for 'there is / have'. In the past, бути agrees with gender: був / була / було / були.","de":"Setzen Sie im Präsens kein 'ist/bin': «Я студент» heißt schon 'ich bin Student'. «є» nur für 'es gibt / haben'. Im Präteritum kongruiert бути im Genus: був / була / було / були.","it":"Non inserire 'sono/è' al presente: «Я студент» significa già 'sono studente'. Usa «є» solo per 'c'è / avere'. Al passato бути concorda nel genere: був / була / було / були.","es_ar":"لا تُدخل «يكون» في المضارع: «Я студент» تعني أصلًا «أنا طالب». استعمل «є» فقط بمعنى «يوجد/لديّ». وفي الماضي يطابق بути الجنس: був / була / було / були.","fr":"N'insérez pas « suis/est » au présent : «Я студент» signifie déjà « je suis étudiant ». Employez «є» seulement pour « il y a / avoir ». Au passé, бути s'accorde en genre : був / була / було / були."}},
{"id":"numerals-counting","icon":"🧮","level":"A1","title":{"uk":"Числівники та лічба","ru":"Числительные и счёт","en":"Numerals & counting","de":"Zahlen & Zählen","it":"Numerali e conteggio","es_ar":"الأعداد والعدّ","fr":"Nombres et comptage"},"intro":{"uk":"Числівник керує відмінком іменника: після «один» — називний однини (один стіл), після «два, три, чотири» — називний множини (два столи, три книги), після «п'ять» і більше — родовий множини (п'ять столів, багато книг). «Один» узгоджується в роді: один, одна, одне.","ru":"Как и в русском, число управляет падежом: 1 → ед.ч. (один стіл), 2–4 → мн.ч. в укр. это НАЗЫВНЫЙ множины (два столи — не «стола»!), 5+ → родительный множины (п'ять столів). Важное отличие: после 2/3/4 украинский ставит именительный мн., а не форму как русский родительный ед.","en":"The numeral controls the noun's case: after 'one' → nominative singular (один стіл); after 2, 3, 4 → nominative plural (два столи, три книги); after 5 and higher → genitive plural (п'ять столів). 'One' agrees in gender: один, одна, одне.","de":"Das Zahlwort steuert den Kasus des Substantivs: nach 'eins' → Nominativ Singular (один стіл); nach 2, 3, 4 → Nominativ Plural (два столи); ab 5 → Genitiv Plural (п'ять столів). 'Eins' kongruiert im Genus: один, одна, одне.","it":"Il numerale regge il caso del nome: dopo 'uno' → nominativo singolare (один стіл); dopo 2, 3, 4 → nominativo plurale (два столи); da 5 in su → genitivo plurale (п'ять столів). 'Uno' concorda nel genere: один, одна, одне.","es_ar":"العدد يحكم حالة الاسم: بعد «واحد» ← الرفع مفرد (один стіл)؛ بعد 2 و3 و4 ← الرفع جمع (два столи)؛ من 5 فصاعدًا ← الجرّ جمع (п'ять столів). و«واحد» يطابق الجنس: один، одна، одне.","fr":"Le numéral commande le cas du nom : après « un » → nominatif singulier (один стіл) ; après 2, 3, 4 → nominatif pluriel (два столи) ; à partir de 5 → génitif pluriel (п'ять столів). « Un » s'accorde en genre : один, одна, одне."},"tables":[{"caption":{"uk":"Числа 1–12 та керування іменником","ru":"Числа 1–12 и управление существительным","en":"Numbers 1–12 and noun government","de":"Zahlen 1–12 und Rektion","it":"Numeri 1–12 e reggenza del nome","es_ar":"الأعداد 1–12 وحُكم الاسم","fr":"Nombres 1–12 et rection du nom"},"labelHeader":{"uk":"Число","ru":"Число","en":"Number","de":"Zahl","it":"Numero","es_ar":"العدد","fr":"Nombre"},"columns":[{"uk":"Числівник","ru":"Числительное","en":"Numeral","de":"Zahlwort","it":"Numerale","es_ar":"العدد","fr":"Numéral"},{"uk":"Форма іменника","ru":"Форма существительного","en":"Noun form","de":"Substantivform","it":"Forma del nome","es_ar":"صيغة الاسم","fr":"Forme du nom"}],"rows":[{"label":{"uk":"1","ru":"1","en":"1","de":"1","it":"1","es_ar":"1","fr":"1"},"cells":["один / одна / одне","один стіл, одна книга"]},{"label":{"uk":"2","ru":"2","en":"2","de":"2","it":"2","es_ar":"2","fr":"2"},"cells":["два / дві","два столи, дві книги"]},{"label":{"uk":"3–4","ru":"3–4","en":"3–4","de":"3–4","it":"3–4","es_ar":"3–4","fr":"3–4"},"cells":["три, чотири","три столи, чотири книги"]},{"label":{"uk":"5–10","ru":"5–10","en":"5–10","de":"5–10","it":"5–10","es_ar":"5–10","fr":"5–10"},"cells":["п'ять, шість, сім, вісім, дев'ять, десять","п'ять столів, десять книг"]},{"label":{"uk":"11–12","ru":"11–12","en":"11–12","de":"11–12","it":"11–12","es_ar":"11–12","fr":"11–12"},"cells":["одинадцять, дванадцять","одинадцять столів"]}]}],"examples":[{"uk":"У мене одна сестра і два брати.","ru":"У меня одна сестра и два брата.","en":"I have one sister and two brothers.","de":"Ich habe eine Schwester und zwei Brüder.","it":"Ho una sorella e due fratelli.","es_ar":"لديّ أختٌ واحدة وأخوان.","fr":"J'ai une sœur et deux frères."},{"uk":"На столі лежить п'ять книг.","ru":"На столе лежит пять книг.","en":"There are five books on the table.","de":"Auf dem Tisch liegen fünf Bücher.","it":"Sul tavolo ci sono cinque libri.","es_ar":"على الطاولة خمسة كتب.","fr":"Il y a cinq livres sur la table."},{"uk":"Скільки тобі років? — Двадцять три.","ru":"Сколько тебе лет? — Двадцать три.","en":"How old are you? — Twenty-three.","de":"Wie alt bist du? — Dreiundzwanzig.","it":"Quanti anni hai? — Ventitré.","es_ar":"كم عمرك؟ — ثلاثة وعشرون.","fr":"Quel âge as-tu ? — Vingt-trois."}],"hints":{"ru":"После 2, 3, 4 украинский требует именительный МНОЖЕСТВЕННОГО (два столи, три сестри), а не «два стола» как в русском. И «дві» — женская форма (дві книги), «два» — мужская/средняя. С 21, 31… последнее слово «один», поэтому «двадцять один стіл».","en":"The key trap: after 2/3/4 use the nominative plural (два столи), not a special singular form. 'Two' has a feminine form дві (дві книги). Compound numbers ending in 1 (21, 31) take the singular: двадцять один стіл.","de":"Falle: nach 2/3/4 steht der Nominativ Plural (два столи). 'Zwei' hat die feminine Form дві (дві книги). Zusammengesetzte Zahlen auf 1 (21, 31) verlangen den Singular: двадцять один стіл.","it":"Trabocchetto: dopo 2/3/4 si usa il nominativo plurale (два столи). 'Due' ha la forma femminile дві (дві книги). I numeri composti che finiscono in 1 (21, 31) reggono il singolare: двадцять один стіл.","es_ar":"الفخّ: بعد 2/3/4 يُستعمل الرفع جمعًا (два столи). و«اثنان» له صيغة مؤنّثة дві (дві книги). والأعداد المركّبة المنتهية بـ 1 (21، 31) تأخذ المفرد: двадцять один стіл.","fr":"Le piège : après 2/3/4, employez le nominatif pluriel (два столи). « Deux » a une forme féminine дві (дві книги). Les nombres composés finissant par 1 (21, 31) exigent le singulier : двадцять один стіл."}},
{"id":"possessives","icon":"🔑","level":"A1","title":{"uk":"Присвійні займенники","ru":"Притяжательные местоимения","en":"Possessives","de":"Possessivpronomen","it":"Possessivi","es_ar":"الضمائر الملكية","fr":"Les possessifs"},"intro":{"uk":"Присвійні займенники узгоджуються в роді, числі й відмінку з тим, чим володіють: мій, моя, моє, мої; твій, твоя, твоє; наш, ваш. Для 3-ї особи використовуються НЕзмінні форми родового відмінка займенника: його (його/її book залежно від власника), її, їхній. «Його» і «її» не змінюються!","ru":"Притяжательные согласуются с обладаемым предметом: мій, моя, моє, мої (мой, моя…). Внимание: для «его/её/их» украинский использует його, її, їхній. «Його» и «її» не склоняются (как в русском «его/её»), а «їхній» склоняется, как прилагательное — в отличие от русского неизменяемого «их».","en":"Possessives agree in gender, number and case with the thing owned: мій/моя/моє/мої, твій, наш, ваш. For the 3rd person, Ukrainian uses його (his/its), її (her), їхній (their). його and її never change form; only їхній declines like an adjective.","de":"Possessivpronomen kongruieren mit dem Besitz in Genus, Zahl und Kasus: мій/моя/моє/мої, твій, наш, ваш. Für die 3. Person: його (sein), її (ihr), їхній (ihr/Pl.). його und її sind unveränderlich; nur їхній wird wie ein Adjektiv dekliniert.","it":"I possessivi concordano con la cosa posseduta in genere, numero e caso: мій/моя/моє/мої, твій, наш, ваш. Per la 3ª persona: його (suo, di lui/esso), її (suo, di lei), їхній (loro). його e її sono invariabili; solo їхній si declina come aggettivo.","es_ar":"الضمائر الملكية تطابق الشيء المملوك في الجنس والعدد والحالة: мій/моя/моє/мої، твій، наш، ваш. وللغائب: його (له)، її (لها)، їхній (لهم). أمّا його وїї فلا يتغيّران؛ ويتصرّف їхній كالصفة فقط.","fr":"Les possessifs s'accordent avec l'objet possédé en genre, nombre et cas : мій/моя/моє/мої, твій, наш, ваш. À la 3e personne : його (à lui), її (à elle), їхній (à eux). його et її sont invariables ; seul їхній se décline comme un adjectif."},"tables":[{"caption":{"uk":"Присвійні за родом володіння (називний)","ru":"Притяжательные по роду обладаемого (именительный)","en":"Possessives by gender of the owned noun (nom.)","de":"Possessiva nach Genus des Besitzes (Nom.)","it":"Possessivi per genere della cosa posseduta (nom.)","es_ar":"الملكية حسب جنس المملوك (الرفع)","fr":"Possessifs selon le genre du possédé (nom.)"},"labelHeader":{"uk":"Власник","ru":"Обладатель","en":"Owner","de":"Besitzer","it":"Possessore","es_ar":"المالك","fr":"Possesseur"},"columns":[{"uk":"ч.р.","ru":"м.р.","en":"masc.","de":"m.","it":"m.","es_ar":"مذكّر","fr":"m."},{"uk":"ж.р.","ru":"ж.р.","en":"fem.","de":"f.","it":"f.","es_ar":"مؤنّث","fr":"f."},{"uk":"с.р.","ru":"ср.р.","en":"neut.","de":"n.","it":"n.","es_ar":"محايد","fr":"n."},{"uk":"мн.","ru":"мн.","en":"pl.","de":"Pl.","it":"pl.","es_ar":"جمع","fr":"pl."}],"rows":[{"label":{"uk":"я → мій","ru":"я → мой","en":"я → my","de":"я → mein","it":"я → mio","es_ar":"я ← لي","fr":"я → mon"},"cells":["мій","моя","моє","мої"]},{"label":{"uk":"ти → твій","ru":"ти → твой","en":"ти → your","de":"ти → dein","it":"ти → tuo","es_ar":"ти ← لك","fr":"ти → ton"},"cells":["твій","твоя","твоє","твої"]},{"label":{"uk":"ми → наш","ru":"ми → наш","en":"ми → our","de":"ми → unser","it":"ми → nostro","es_ar":"ми ← لنا","fr":"ми → notre"},"cells":["наш","наша","наше","наші"]},{"label":{"uk":"ви → ваш","ru":"ви → ваш","en":"ви → your","de":"ви → euer/Ihr","it":"ви → vostro","es_ar":"ви ← لكم","fr":"ви → votre"},"cells":["ваш","ваша","ваше","ваші"]},{"label":{"uk":"він/вона/вони","ru":"он/она/они","en":"he/she/they","de":"er/sie/sie","it":"lui/lei/loro","es_ar":"هو/هي/هم","fr":"il/elle/ils"},"cells":["його / її / їхній","його / її / їхня","його / її / їхнє","його / її / їхні"]}]}],"examples":[{"uk":"Це мій дім і моя машина.","ru":"Это мой дом и моя машина.","en":"This is my house and my car.","de":"Das ist mein Haus und mein Auto.","it":"Questa è la mia casa e la mia auto.","es_ar":"هذا بيتي وهذه سيّارتي.","fr":"C'est ma maison et ma voiture."},{"uk":"Її брат і його сестра — студенти.","ru":"Её брат и его сестра — студенты.","en":"Her brother and his sister are students.","de":"Ihr Bruder und seine Schwester sind Studenten.","it":"Suo fratello (di lei) e sua sorella (di lui) sono studenti.","es_ar":"أخوها وأخته طالبان.","fr":"Son frère (à elle) et sa sœur (à lui) sont étudiants."},{"uk":"Де ваш квиток? — Ось наші квитки.","ru":"Где ваш билет? — Вот наши билеты.","en":"Where is your ticket? — Here are our tickets.","de":"Wo ist Ihr Ticket? — Hier sind unsere Tickets.","it":"Dov'è il vostro biglietto? — Ecco i nostri biglietti.","es_ar":"أين تذكرتكم؟ — ها هي تذاكرنا.","fr":"Où est votre billet ? — Voici nos billets."}],"hints":{"ru":"«Його» и «її» не изменяются: його книга, його книги, з його книгою. А «їхній» склоняется (їхня хата, їхні діти) — не путайте с русским неизменяемым «их». Мій/твій согласуются с обладаемым, а не с обладателем.","en":"Match the possessive to the thing owned, not the owner: моя книга (fem. book) even if 'I' am male. його and її are frozen — они never inflect. But їхній declines fully (їхня хата, їхні діти).","de":"Richten Sie das Possessivum nach dem Besitz, nicht dem Besitzer: моя книга (f.), auch wenn 'ich' männlich bin. його und її sind unveränderlich; їхній dagegen wird dekliniert (їхня хата).","it":"Accorda il possessivo con la cosa posseduta, non col possessore: моя книга (f.) anche se 'io' sono maschio. його e її sono invariabili; його invece їхній si declina (їхня хата).","es_ar":"طابِق الضمير الملكي مع المملوك لا المالك: моя книга (مؤنّث) ولو كان المتكلّم ذكرًا. його وїї لا يتغيّران؛ أمّا їхній فيُصرَّف (їхня хата).","fr":"Accordez le possessif avec l'objet possédé, pas le possesseur : моя книга (f.) même si « je » suis un homme. його et її sont invariables ; en revanche їхній se décline (їхня хата)."}},
{"id":"questions-negation","icon":"❓","level":"A1","title":{"uk":"Питання та заперечення","ru":"Вопросы и отрицание","en":"Questions & negation","de":"Fragen & Verneinung","it":"Domande e negazione","es_ar":"الأسئلة والنفي","fr":"Questions et négation"},"intro":{"uk":"Питання так/ні часто утворюють часткою «чи» на початку або лише інтонацією: «Ти вдома?» = «Чи ти вдома?». Спеціальні питання починають зі слів: хто, що, де, коли, чому, як, скільки, який. Заперечення — частка «не» перед словом; при запереченні дієслова додаток часто стає в родовому відмінку.","ru":"Вопрос да/нет — частица «чи» в начале или интонация: «Ти студент?». Вопросительные слова: хто, що, де, коли, чому, як. Отрицание — «не» перед словом (украинское «не», не «нет»). При отрицании прямое дополнение часто переходит в родительный падеж: «Я не маю грошей» (не «гроші»).","en":"Yes/no questions use the particle «чи» at the start or just intonation: «Ти вдома?» = 'Are you home?'. Wh-words: хто (who), що (what), де (where), коли (when), чому (why), як (how). Negation is «не» before the word; a negated verb's object often shifts to the genitive.","de":"Ja/Nein-Fragen bildet man mit «чи» am Satzanfang oder nur durch Intonation: «Ти вдома?». Fragewörter: хто, що, де, коли, чому, як. Verneinung mit «не» vor dem Wort; das Objekt eines verneinten Verbs steht oft im Genitiv.","it":"Le domande sì/no usano la particella «чи» all'inizio o solo l'intonazione: «Ти вдома?». Interrogativi: хто, що, де, коли, чому, як. La negazione è «не» prima della parola; l'oggetto di un verbo negato passa spesso al genitivo.","es_ar":"أسئلة نعم/لا تُصاغ بالأداة «чи» في البداية أو بالنبرة فقط: «Ти вдома?». أدوات الاستفهام: хто، що، де، коли, чому، як. والنفي بـ «не» قبل الكلمة؛ ومفعول الفعل المنفيّ يتحوّل غالبًا إلى حالة الجرّ.","fr":"Les questions oui/non emploient la particule «чи» en tête ou la seule intonation : «Ти вдома?». Mots interrogatifs : хто, що, де, коли, чому, як. La négation est «не» devant le mot ; l'objet d'un verbe nié passe souvent au génitif."},"tables":[{"caption":{"uk":"Питальні слова","ru":"Вопросительные слова","en":"Question words","de":"Fragewörter","it":"Parole interrogative","es_ar":"أدوات الاستفهام","fr":"Mots interrogatifs"},"labelHeader":{"uk":"Значення","ru":"Значение","en":"Meaning","de":"Bedeutung","it":"Significato","es_ar":"المعنى","fr":"Sens"},"columns":[{"uk":"Слово","ru":"Слово","en":"Word","de":"Wort","it":"Parola","es_ar":"الكلمة","fr":"Mot"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"хто?","ru":"кто?","en":"who?","de":"wer?","it":"chi?","es_ar":"مَن؟","fr":"qui ?"},"cells":["хто","Хто це?"]},{"label":{"uk":"що?","ru":"что?","en":"what?","de":"was?","it":"che cosa?","es_ar":"ماذا؟","fr":"quoi ?"},"cells":["що","Що ти робиш?"]},{"label":{"uk":"де?","ru":"где?","en":"where?","de":"wo?","it":"dove?","es_ar":"أين؟","fr":"où ?"},"cells":["де","Де ти живеш?"]},{"label":{"uk":"коли?","ru":"когда?","en":"when?","de":"wann?","it":"quando?","es_ar":"متى؟","fr":"quand ?"},"cells":["коли","Коли ти прийдеш?"]},{"label":{"uk":"чому?","ru":"почему?","en":"why?","de":"warum?","it":"perché?","es_ar":"لماذا؟","fr":"pourquoi ?"},"cells":["чому","Чому ти сумний?"]},{"label":{"uk":"як?","ru":"как?","en":"how?","de":"wie?","it":"come?","es_ar":"كيف؟","fr":"comment ?"},"cells":["як","Як тебе звати?"]}]}],"examples":[{"uk":"Чи ти розмовляєш англійською?","ru":"Ты говоришь по-английски?","en":"Do you speak English?","de":"Sprichst du Englisch?","it":"Parli inglese?","es_ar":"هل تتكلّم الإنجليزية؟","fr":"Parles-tu anglais ?"},{"uk":"Я не знаю, де вона.","ru":"Я не знаю, где она.","en":"I don't know where she is.","de":"Ich weiß nicht, wo sie ist.","it":"Non so dove sia.","es_ar":"لا أعرف أين هي.","fr":"Je ne sais pas où elle est."},{"uk":"У мене немає часу.","ru":"У меня нет времени.","en":"I have no time.","de":"Ich habe keine Zeit.","it":"Non ho tempo.","es_ar":"ليس لديّ وقت.","fr":"Je n'ai pas le temps."}],"hints":{"ru":"«Немає» + родительный падеж выражает отсутствие: «немає часу», «немає грошей» (не «немає час»). При отрицании прямого дополнения ставьте родительный: «Я не бачу машини». «Чи» ставится только в начале вопроса, а не как русское «ли» после слова.","en":"Use «немає» + genitive for 'there isn't / I don't have': немає часу. After a negated verb, put the object in the genitive: «Я не бачу машини». Unlike English, double negation is required: «Я нічого не знаю» ('I know nothing').","de":"«немає» + Genitiv heißt 'es gibt kein / ich habe kein': немає часу. Nach verneintem Verb steht das Objekt im Genitiv. Anders als im Deutschen ist doppelte Verneinung Pflicht: «Я нічого не знаю».","it":"«немає» + genitivo significa 'non c'è / non ho': немає часу. Dopo un verbo negato l'oggetto va al genitivo. Come in italiano, serve la doppia negazione: «Я нічого не знаю» ('non so niente').","es_ar":"«немає» + الجرّ تعني «لا يوجد / ليس لديّ»: немає часу. وبعد الفعل المنفيّ يأتي المفعول في حالة الجرّ. والنفي المزدوج إلزاميّ: «Я нічого не знаю» (لا أعرف شيئًا).","fr":"«немає» + génitif signifie « il n'y a pas / je n'ai pas » : немає часу. Après un verbe nié, l'objet passe au génitif. Comme en français, la double négation est de règle : «Я нічого не знаю» (je ne sais rien)."}},
{"id":"nominative-accusative","icon":"🎯","level":"A2","title":{"uk":"Називний та знахідний відмінки","ru":"Именительный и винительный падежи","en":"Nominative & accusative","de":"Nominativ & Akkusativ","it":"Nominativo e accusativo","es_ar":"حالتا الرفع والنصب","fr":"Nominatif et accusatif"},"intro":{"uk":"Називний (хто? що?) — це підмет і словникова форма. Знахідний (кого? що?) — це прямий додаток. Правило: для неістот чоловічого й середнього роду знахідний = називний (бачу стіл), для істот чоловічого роду знахідний = родовий (бачу брата). Жіночий рід на -а має власне закінчення -у: книга → бачу книгу.","ru":"Именительный — подлежащее (хто? що?), винительный — прямое дополнение (кого? що?). Как в русском: у одушевлённых м.р. вин.=род. (бачу брата), у неодушевлённых м.р. вин.=им. (бачу стіл). Женский на -а даёт -у: книга → книгу. Отличие от русского в деталях окончаний, но логика та же.","en":"The nominative (хто? що?) is the subject and dictionary form; the accusative (кого? що?) is the direct object. Rule: for masculine/neuter inanimates, accusative = nominative (бачу стіл); for masculine animates, accusative = genitive (бачу брата). Feminine -а nouns take -у: книга → книгу.","de":"Der Nominativ (хто? що?) ist Subjekt und Grundform; der Akkusativ (кого? що?) das direkte Objekt. Regel: bei maskulinen/neutralen Unbelebten Akkusativ = Nominativ (бачу стіл); bei belebten Maskulina Akkusativ = Genitiv (бачу брата). Feminina auf -а: -у (книгу).","it":"Il nominativo (хто? що?) è il soggetto e la forma base; l'accusativo (кого? що?) è l'oggetto diretto. Regola: per inanimati maschili/neutri accusativo = nominativo (бачу стіл); per animati maschili accusativo = genitivo (бачу брата). Femminili in -а: -у (книгу).","es_ar":"حالة الرفع (хто? що?) للفاعل والصيغة القاموسية؛ وحالة النصب (кого? що?) للمفعول المباشر. القاعدة: لغير العاقل المذكّر/المحايد النصب = الرفع (бачу стіл)؛ وللعاقل المذكّر النصب = الجرّ (бачу брата). والمؤنّث بـ -а يأخذ -у (книгу).","fr":"Le nominatif (хто? що?) est le sujet et la forme de base ; l'accusatif (кого? що?) est l'objet direct. Règle : pour les inanimés masculins/neutres, accusatif = nominatif (бачу стіл) ; pour les animés masculins, accusatif = génitif (бачу брата). Féminins en -а : -у (книгу)."},"tables":[{"caption":{"uk":"Знахідний відмінок за типом іменника","ru":"Винительный падеж по типу существительного","en":"Accusative by noun type","de":"Akkusativ nach Substantivtyp","it":"Accusativo per tipo di nome","es_ar":"حالة النصب حسب نوع الاسم","fr":"Accusatif selon le type de nom"},"labelHeader":{"uk":"Тип іменника","ru":"Тип существительного","en":"Noun type","de":"Substantivtyp","it":"Tipo di nome","es_ar":"نوع الاسم","fr":"Type de nom"},"columns":[{"uk":"Називний","ru":"Именительный","en":"Nominative","de":"Nominativ","it":"Nominativo","es_ar":"الرفع","fr":"Nominatif"},{"uk":"Знахідний","ru":"Винительный","en":"Accusative","de":"Akkusativ","it":"Accusativo","es_ar":"النصب","fr":"Accusatif"}],"rows":[{"label":{"uk":"ч.р. неістота","ru":"м.р. неодуш.","en":"masc. inanimate","de":"m. unbelebt","it":"m. inanimato","es_ar":"مذكّر غير عاقل","fr":"m. inanimé"},"cells":["стіл, чай","бачу стіл, п'ю чай"]},{"label":{"uk":"ч.р. істота","ru":"м.р. одуш.","en":"masc. animate","de":"m. belebt","it":"m. animato","es_ar":"مذكّر عاقل","fr":"m. animé"},"cells":["брат, кіт","бачу брата, кота"]},{"label":{"uk":"ж.р. на -а","ru":"ж.р. на -а","en":"fem. in -а","de":"f. auf -а","it":"f. in -а","es_ar":"مؤنّث بـ -а","fr":"f. en -а"},"cells":["книга, сестра","читаю книгу, бачу сестру"]},{"label":{"uk":"с.р.","ru":"ср.р.","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["вікно, море","бачу вікно, море"]},{"label":{"uk":"ж.р. на -ь","ru":"ж.р. на -ь","en":"fem. in -ь","de":"f. auf -ь","it":"f. in -ь","es_ar":"مؤنّث بـ -ь","fr":"f. en -ь"},"cells":["ніч, сіль","бачу ніч, кладу сіль"]}]}],"examples":[{"uk":"Хлопчик читає книгу.","ru":"Мальчик читает книгу.","en":"The boy is reading a book.","de":"Der Junge liest ein Buch.","it":"Il ragazzo legge un libro.","es_ar":"الولد يقرأ كتابًا.","fr":"Le garçon lit un livre."},{"uk":"Я бачу брата і сестру.","ru":"Я вижу брата и сестру.","en":"I see my brother and sister.","de":"Ich sehe meinen Bruder und meine Schwester.","it":"Vedo mio fratello e mia sorella.","es_ar":"أرى أخي وأختي.","fr":"Je vois mon frère et ma sœur."},{"uk":"Ми купуємо хліб і молоко.","ru":"Мы покупаем хлеб и молоко.","en":"We are buying bread and milk.","de":"Wir kaufen Brot und Milch.","it":"Compriamo pane e latte.","es_ar":"نشتري خبزًا وحليبًا.","fr":"Nous achetons du pain et du lait."}],"hints":{"ru":"Ключевое: для одушевлённых м.р. вин.=род. (бачу брата, а не «бачу брат»), для неодушевлённых вин.=им. (бачу стіл). Женский -а → -у (книгу). Проверяйте одушевлённость: тварини тоже одушевлённые (бачу кота).","en":"The animacy split is the crux: masculine animate accusative copies the genitive (бачу брата), inanimate copies the nominative (бачу стіл). This applies to animals too (бачу кота). Feminine -а always becomes -у.","de":"Entscheidend ist die Belebtheit: belebte Maskulina bilden den Akkusativ wie den Genitiv (бачу брата), unbelebte wie den Nominativ (бачу стіл) — auch bei Tieren (бачу кота). Feminina auf -а werden immer -у.","it":"Il nodo è l'animatezza: i maschili animati fanno l'accusativo come il genitivo (бачу брата), gli inanimati come il nominativo (бачу стіл), anche per gli animali (бачу кота). I femminili in -а diventano sempre -у.","es_ar":"المحور هو العاقلية: العاقل المذكّر ينصب كالجرّ (бачу брата)، وغير العاقل كالرفع (бачу стіл)، ويشمل ذلك الحيوانات (бачу кота). والمؤنّث بـ -а يصير دائمًا -у.","fr":"Le point clé est l'animéité : les masculins animés forment l'accusatif comme le génitif (бачу брата), les inanimés comme le nominatif (бачу стіл), y compris pour les animaux (бачу кота). Les féminins en -а deviennent toujours -у."}},
{"id":"genitive","icon":"🧷","level":"A2","title":{"uk":"Родовий відмінок","ru":"Родительный падеж","en":"Genitive case","de":"Genitiv","it":"Genitivo","es_ar":"حالة الجرّ (المضاف إليه)","fr":"Génitif"},"intro":{"uk":"Родовий (кого? чого?) означає належність (книга брата), відсутність (немає часу), кількість (склянка води, багато людей), а також після чисел 5+. Закінчення: ч.р. -а/-я або -у/-ю (стола/столу), ж.р. -и/-і (сестри, землі), с.р. -а/-я (вікна, моря), множина часто нульове (книг) або -ів (столів).","ru":"Родительный (кого? чого?) — принадлежность (книга брата), отсутствие (немає часу), количество (склянка води), после чисел 5+. Внимание на м.р.: часто есть выбор -а/-у (стола vs столу) — конкретные предметы обычно -а, вещества/абстракции -у. В отличие от русского эта вариативность выражена сильнее.","en":"The genitive (кого? чого?) marks possession (книга брата), absence (немає часу), quantity (склянка води, багато людей), and follows numbers 5+. Endings: masc. -а/-я or -у/-ю (стола/столу), fem. -и/-і, neut. -а/-я, plural often zero (книг) or -ів (столів).","de":"Der Genitiv (кого? чого?) drückt Besitz (книга брата), Fehlen (немає часу), Menge (склянка води) aus und folgt Zahlen ab 5. Endungen: m. -а/-я oder -у/-ю (стола/столу), f. -и/-і, n. -а/-я, Plural oft endungslos (книг) oder -ів (столів).","it":"Il genitivo (кого? чого?) indica possesso (книга брата), assenza (немає часу), quantità (склянка води) e segue i numeri da 5. Desinenze: m. -а/-я o -у/-ю (стола/столу), f. -и/-і, n. -а/-я, plurale spesso a desinenza zero (книг) o -ів (столів).","es_ar":"حالة الجرّ (кого? чого?) تدلّ على المِلك (книга брата) والغياب (немає часу) والكمّية (склянка води) وتأتي بعد الأعداد 5 فأكثر. النهايات: مذكّر -а/-я أو -у/-ю (стола/столу)، مؤنّث -и/-і، محايد -а/-я، والجمع بلا نهاية غالبًا (книг) أو -ів (столів).","fr":"Le génitif (кого? чого?) marque la possession (книга брата), l'absence (немає часу), la quantité (склянка води) et suit les nombres à partir de 5. Terminaisons : m. -а/-я ou -у/-ю (стола/столу), f. -и/-і, n. -а/-я, pluriel souvent sans désinence (книг) ou -ів (столів)."},"tables":[{"caption":{"uk":"Родовий відмінок однини","ru":"Родительный падеж единственного числа","en":"Genitive singular","de":"Genitiv Singular","it":"Genitivo singolare","es_ar":"الجرّ في المفرد","fr":"Génitif singulier"},"labelHeader":{"uk":"Рід","ru":"Род","en":"Gender","de":"Genus","it":"Genere","es_ar":"الجنس","fr":"Genre"},"columns":[{"uk":"Називний","ru":"Именительный","en":"Nominative","de":"Nominativ","it":"Nominativo","es_ar":"الرفع","fr":"Nominatif"},{"uk":"Родовий","ru":"Родительный","en":"Genitive","de":"Genitiv","it":"Genitivo","es_ar":"الجرّ","fr":"Génitif"}],"rows":[{"label":{"uk":"ч.р. (предмет)","ru":"м.р. (предмет)","en":"masc. (object)","de":"m. (Ding)","it":"m. (oggetto)","es_ar":"مذكّر (شيء)","fr":"m. (objet)"},"cells":["брат, стіл","брата, стола/столу"]},{"label":{"uk":"ч.р. (речовина)","ru":"м.р. (вещество)","en":"masc. (mass)","de":"m. (Stoff)","it":"m. (materia)","es_ar":"مذكّر (مادّة)","fr":"m. (matière)"},"cells":["цукор, чай","цукру, чаю"]},{"label":{"uk":"ж.р. на -а","ru":"ж.р. на -а","en":"fem. -а","de":"f. -а","it":"f. -а","es_ar":"مؤنّث -а","fr":"f. -а"},"cells":["сестра, книга","сестри, книги"]},{"label":{"uk":"с.р.","ru":"ср.р.","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["вікно, море","вікна, моря"]},{"label":{"uk":"множина","ru":"множ.","en":"plural","de":"Plural","it":"plurale","es_ar":"جمع","fr":"pluriel"},"cells":["книги, столи","книг, столів"]}]}],"examples":[{"uk":"Це книга мого брата.","ru":"Это книга моего брата.","en":"This is my brother's book.","de":"Das ist das Buch meines Bruders.","it":"Questo è il libro di mio fratello.","es_ar":"هذا كتاب أخي.","fr":"C'est le livre de mon frère."},{"uk":"Дай мені склянку води, будь ласка.","ru":"Дай мне стакан воды, пожалуйста.","en":"Give me a glass of water, please.","de":"Gib mir bitte ein Glas Wasser.","it":"Dammi un bicchiere d'acqua, per favore.","es_ar":"أعطني كأس ماء من فضلك.","fr":"Donne-moi un verre d'eau, s'il te plaît."},{"uk":"У місті багато людей і мало машин.","ru":"В городе много людей и мало машин.","en":"There are many people and few cars in the city.","de":"In der Stadt gibt es viele Menschen und wenige Autos.","it":"In città c'è molta gente e poche macchine.","es_ar":"في المدينة أناسٌ كثيرون وسيّاراتٌ قليلة.","fr":"Dans la ville il y a beaucoup de gens et peu de voitures."},{"uk":"Я з України.","ru":"Я из Украины.","en":"I am from Ukraine.","de":"Ich komme aus der Ukraine.","it":"Vengo dall'Ucraina.","es_ar":"أنا من أوكرانيا.","fr":"Je viens d'Ukraine."}],"hints":{"ru":"У существительных м.р. выбирайте -а для считаемых предметов/людей (стола, брата) и -у для веществ и абстракций (цукру, снігу, миру). После «немає», «багато», «мало», чисел 5+ и предлогов «з, від, до, без» — родительный.","en":"Masculine nouns choose -а for countable objects/people (стола, брата) but -у for masses and abstractions (цукру, снігу). The genitive follows немає, багато/мало, numbers 5+, and prepositions з, від, до, без.","de":"Maskulina wählen -а für zählbare Dinge/Personen (стола, брата), -у für Stoffe und Abstrakta (цукру, снігу). Der Genitiv folgt auf немає, багато/мало, Zahlen ab 5 und die Präpositionen з, від, до, без.","it":"I maschili scelgono -а per oggetti/persone numerabili (стола, брата), -у per materie e astratti (цукру, снігу). Il genitivo segue немає, багато/мало, i numeri da 5 e le preposizioni з, від, до, без.","es_ar":"الأسماء المذكّرة تأخذ -а للأشياء/الأشخاص المعدودين (стола، брата) و-у للموادّ والمجرّدات (цукру، снігу). ويأتي الجرّ بعد немає وбагато/мало والأعداد 5+ وحروف з، від، до، без.","fr":"Les masculins prennent -а pour les objets/personnes comptables (стола, брата) et -у pour les matières et abstraits (цукру, снігу). Le génitif suit немає, багато/мало, les nombres à partir de 5 et les prépositions з, від, до, без."}},
{"id":"dative","icon":"🎁","level":"A2","title":{"uk":"Давальний відмінок","ru":"Дательный падеж","en":"Dative case","de":"Dativ","it":"Dativo","es_ar":"حالة الإسناد (المفعول له)","fr":"Datif"},"intro":{"uk":"Давальний (кому? чому?) означає адресата дії (даю братові), а також вік і стан у безособових зворотах (мені холодно, їй двадцять років). Закінчення: ч.р. -ові/-еві або -у/-ю (братові/брату), ж.р. -і/-ї (сестрі, землі), с.р. -у/-ю (вікну, морю), множина -ам/-ям (братам).","ru":"Дательный (кому? чому?) — адресат (даю братові), а также состояние и возраст в безличных оборотах: «мені холодно», «їй двадцять років». Отличие от русского: у м.р. одуш. очень употребительно окончание -ові/-еві (братові, синові), а не только -у, как в русском.","en":"The dative (кому? чому?) marks the recipient (даю братові = 'I give to my brother') and appears in impersonal expressions of state and age (мені холодно = 'I'm cold', їй двадцять років). Endings: masc. -ові/-еві or -у/-ю, fem. -і/-ї, neut. -у/-ю, plural -ам/-ям.","de":"Der Dativ (кому? чому?) bezeichnet den Empfänger (даю братові) und steht in unpersönlichen Ausdrücken von Zustand und Alter (мені холодно, їй двадцять років). Endungen: m. -ові/-еві oder -у/-ю, f. -і/-ї, n. -у/-ю, Plural -ам/-ям.","it":"Il dativo (кому? чому?) indica il destinatario (даю братові) e compare in espressioni impersonali di stato ed età (мені холодно, їй двадцять років). Desinenze: m. -ові/-еві o -у/-ю, f. -і/-ї, n. -у/-ю, plurale -ам/-ям.","es_ar":"حالة الإسناد (кому? чому?) تدلّ على المُتلقّي (даю братові) وتظهر في التعابير غير الشخصية للحالة والعمر (мені холодно، їй двадцять років). النهايات: مذكّر -ові/-еві أو -у/-ю، مؤنّث -і/-ї، محايد -у/-ю، جمع -ам/-ям.","fr":"Le datif (кому? чому?) marque le destinataire (даю братові) et apparaît dans les tournures impersonnelles d'état et d'âge (мені холодно, їй двадцять років). Terminaisons : m. -ові/-еві ou -у/-ю, f. -і/-ї, n. -у/-ю, pluriel -ам/-ям."},"tables":[{"caption":{"uk":"Давальний відмінок","ru":"Дательный падеж","en":"Dative case","de":"Dativ","it":"Dativo","es_ar":"حالة الإسناد","fr":"Datif"},"labelHeader":{"uk":"Слово","ru":"Слово","en":"Word","de":"Wort","it":"Parola","es_ar":"الكلمة","fr":"Mot"},"columns":[{"uk":"Називний","ru":"Именительный","en":"Nominative","de":"Nominativ","it":"Nominativo","es_ar":"الرفع","fr":"Nominatif"},{"uk":"Давальний","ru":"Дательный","en":"Dative","de":"Dativ","it":"Dativo","es_ar":"الإسناد","fr":"Datif"}],"rows":[{"label":{"uk":"ч.р. істота","ru":"м.р. одуш.","en":"masc. animate","de":"m. belebt","it":"m. animato","es_ar":"مذكّر عاقل","fr":"m. animé"},"cells":["брат, син","братові/брату, синові/сину"]},{"label":{"uk":"ж.р. на -а","ru":"ж.р. на -а","en":"fem. -а","de":"f. -а","it":"f. -а","es_ar":"مؤنّث -а","fr":"f. -а"},"cells":["сестра, мама","сестрі, мамі"]},{"label":{"uk":"с.р.","ru":"ср.р.","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["вікно, дитя","вікну, дитяті"]},{"label":{"uk":"займенники","ru":"местоимения","en":"pronouns","de":"Pronomen","it":"pronomi","es_ar":"الضمائر","fr":"pronoms"},"cells":["я, ти, він, вона","мені, тобі, йому, їй"]},{"label":{"uk":"множина","ru":"множ.","en":"plural","de":"Plural","it":"plurale","es_ar":"جمع","fr":"pluriel"},"cells":["брати, діти","братам, дітям"]}]}],"examples":[{"uk":"Я дарую мамі квіти.","ru":"Я дарю маме цветы.","en":"I am giving my mum flowers.","de":"Ich schenke meiner Mutter Blumen.","it":"Regalo dei fiori a mia madre.","es_ar":"أُهدي أمّي زهورًا.","fr":"J'offre des fleurs à ma mère."},{"uk":"Мені холодно, а тобі?","ru":"Мне холодно, а тебе?","en":"I'm cold — and you?","de":"Mir ist kalt — und dir?","it":"Ho freddo — e tu?","es_ar":"أشعر بالبرد — وأنتَ؟","fr":"J'ai froid — et toi ?"},{"uk":"Скільки років твоєму братові? — Йому десять.","ru":"Сколько лет твоему брату? — Ему десять.","en":"How old is your brother? — He is ten.","de":"Wie alt ist dein Bruder? — Er ist zehn.","it":"Quanti anni ha tuo fratello? — Ha dieci anni.","es_ar":"كم عمر أخيك؟ — عمره عشر سنوات.","fr":"Quel âge a ton frère ? — Il a dix ans."}],"hints":{"ru":"У одушевлённых м.р. предпочитайте -ові/-еві (братові, синові, учителеві) — это очень характерно для украинского, в отличие от русского -у. Возраст и состояние выражаются дательным: «мені сумно», «дитині три роки».","en":"For masculine animate nouns, the ending -ові/-еві is the natural choice (братові, учителеві) — a hallmark of Ukrainian. Use the dative for age and states of being: «мені сумно» ('I feel sad'), «дитині три роки».","de":"Bei belebten Maskulina ist -ові/-еві die natürliche Wahl (братові, учителеві) — typisch Ukrainisch. Der Dativ steht für Alter und Befinden: «мені сумно», «дитині три роки».","it":"Per i maschili animati la desinenza -ові/-еві è la scelta naturale (братові, учителеві), tratto tipico dell'ucraino. Usa il dativo per età e stati d'animo: «мені сумно», «дитині три роки».","es_ar":"للأسماء المذكّرة العاقلة تكون النهاية -ові/-еві هي الطبيعية (братові، учителеві) وهي سمة أوكرانية. واستعمل الإسناد للعمر والحالات: «мені сумно»، «дитині три роки».","fr":"Pour les masculins animés, la terminaison -ові/-еві est le choix naturel (братові, учителеві), un trait typique de l'ukrainien. Employez le datif pour l'âge et les états : «мені сумно», «дитині три роки»."}},
{"id":"vocative-case","icon":"📣","level":"A2","title":{"uk":"Кличний відмінок","ru":"Звательный падеж","en":"Vocative case","de":"Vokativ","it":"Vocativo","es_ar":"حالة النداء","fr":"Vocatif"},"intro":{"uk":"Кличний відмінок — окрема форма для звертання до людини. В українській він обов'язковий: не «Іван!», а «Іване!». Чоловічий рід з твердою основою бере -е (брат → брате), після г/к/х відбувається чергування (друг → друже, козак → козаче), м'яка основа — -ю (учитель → учителю, Андрій → Андрію). Жіночий рід з твердою основою бере -о (мама → мамо, Оксана → Оксано), м'яка основа — -е (Марія → Маріє), а пестливі на -я — -ю (бабуся → бабусю).","ru":"В украинском есть отдельный звательный падеж, и он ОБЯЗАТЕЛЕН при обращении, в отличие от русского, где обращаются формой именительного. Не «Іван!», а «Іване!»; не «мама!», а «мамо!». Мужской род: -е (брате), после г/к/х чередование (друже, козаче), мягкая основа -ю (учителю). Женский: -о (мамо, Оксано), мягкая -е (Маріє).","en":"Ukrainian keeps a full vocative case for addressing someone, and using it is obligatory: say «Іване!», not «Іван!». Hard-stem masculine nouns take -е (брат → брате), with a consonant shift after г/к/х (друг → друже, козак → козаче); soft stems take -ю (учитель → учителю). Hard-stem feminine nouns take -о (мама → мамо, Оксана → Оксано), soft stems take -е (Марія → Маріє), and pet forms in -я take -ю (бабуся → бабусю).","de":"Das Ukrainische besitzt einen eigenen Vokativ für die Anrede, und er ist obligatorisch: man sagt «Іване!», nicht «Іван!». Maskuline Nomen mit hartem Stamm nehmen -е (брат → брате), nach г/к/х mit Konsonantenwechsel (друг → друже, козак → козаче); weiche Stämme nehmen -ю (учитель → учителю). Feminine harte Stämme nehmen -о (мама → мамо, Оксана → Оксано), weiche -е (Марія → Маріє), Koseformen auf -я nehmen -ю (бабуся → бабусю).","it":"L'ucraino mantiene un vero vocativo per rivolgersi a qualcuno, ed è obbligatorio: si dice «Іване!», non «Іван!». I nomi maschili a tema duro prendono -е (брат → брате), con alternanza dopo г/к/х (друг → друже, козак → козаче); i temi molli prendono -ю (учитель → учителю). I femminili duri prendono -о (мама → мамо, Оксана → Оксано), i molli -е (Марія → Маріє), i vezzeggiativi in -я prendono -ю (бабуся → бабусю).","es_ar":"تحتفظ الأوكرانية بحالة نداء مستقلة عند مخاطبة شخص، واستعمالها إلزامي: نقول «Іване!» لا «Іван!». الأسماء المذكّرة ذات الجذر الصلب تأخذ -е (брат → брате) مع تبادل بعد г/к/х (друг → друже، козак → козаче)؛ والجذور اللينة تأخذ -ю (учитель → учителю). والمؤنّث الصلب يأخذ -о (мама → мамо، Оксана → Оксано)، واللين -е (Марія → Маріє)، وصيغ التحبّب على -я تأخذ -ю (бабуся → бабусю).","fr":"L'ukrainien conserve un vrai vocatif pour s'adresser à quelqu'un, et son emploi est obligatoire : on dit «Іване!», et non «Іван!». Les noms masculins à radical dur prennent -е (брат → брате), avec alternance après г/к/х (друг → друже, козак → козаче) ; les radicaux mous prennent -ю (учитель → учителю). Les féminins durs prennent -о (мама → мамо, Оксана → Оксано), les mous -е (Марія → Маріє), et les formes affectueuses en -я prennent -ю (бабуся → бабусю)."},"tables":[{"caption":{"uk":"Утворення кличного відмінка","ru":"Образование звательного падежа","en":"Forming the vocative","de":"Bildung des Vokativs","it":"Formazione del vocativo","es_ar":"تكوين حالة النداء","fr":"Formation du vocatif"},"labelHeader":{"uk":"Тип основи","ru":"Тип основы","en":"Stem type","de":"Stammtyp","it":"Tipo di tema","es_ar":"نوع الجذر","fr":"Type de radical"},"columns":[{"uk":"Називний","ru":"Именительный","en":"Nominative","de":"Nominativ","it":"Nominativo","es_ar":"حالة الرفع","fr":"Nominatif"},{"uk":"Кличний","ru":"Звательный","en":"Vocative","de":"Vokativ","it":"Vocativo","es_ar":"حالة النداء","fr":"Vocatif"}],"rows":[{"label":{"uk":"чол. тверда основа → -е","ru":"муж. твёрдая основа → -е","en":"masc. hard → -е","de":"mask. hart → -е","it":"masch. duro → -е","es_ar":"مذكّر صلب ← -е","fr":"masc. dur → -е"},"cells":["брат, Іван, пан","брате, Іване, пане"]},{"label":{"uk":"чол. на г/к/х (чергування)","ru":"муж. на г/к/х (чередование)","en":"masc. г/к/х (shift)","de":"mask. г/к/х (Wechsel)","it":"masch. г/к/х (alternanza)","es_ar":"مذكّر г/к/х (تبادل)","fr":"masc. г/к/х (alternance)"},"cells":["друг, козак, Олег","друже, козаче, Олеже"]},{"label":{"uk":"чол. м'яка основа → -ю","ru":"муж. мягкая основа → -ю","en":"masc. soft → -ю","de":"mask. weich → -ю","it":"masch. molle → -ю","es_ar":"مذكّر لين ← -ю","fr":"masc. mou → -ю"},"cells":["учитель, лікар, Андрій","учителю, лікарю, Андрію"]},{"label":{"uk":"жін. тверда основа → -о","ru":"жен. твёрдая основа → -о","en":"fem. hard → -о","de":"fem. hart → -о","it":"femm. duro → -о","es_ar":"مؤنّث صلب ← -о","fr":"fém. dur → -о"},"cells":["мама, сестра, Оксана","мамо, сестро, Оксано"]},{"label":{"uk":"жін. м'яка основа → -е","ru":"жен. мягкая основа → -е","en":"fem. soft → -е","de":"fem. weich → -е","it":"femm. molle → -е","es_ar":"مؤنّث لين ← -е","fr":"fém. mou → -е"},"cells":["Марія, земля, Настя","Маріє, земле, Насте"]},{"label":{"uk":"пестливі на -я → -ю","ru":"ласкательные на -я → -ю","en":"pet forms in -я → -ю","de":"Koseformen auf -я → -ю","it":"vezzeggiativi in -я → -ю","es_ar":"صيغ التحبّب على -я ← -ю","fr":"formes affectueuses en -я → -ю"},"cells":["бабуся, Наталя, матуся","бабусю, Наталю, матусю"]}]}],"examples":[{"uk":"Добрий день, пане Іване! Як ваші справи?","ru":"Добрый день, господин Иван! Как ваши дела?","en":"Good afternoon, Mr Ivan! How are you?","de":"Guten Tag, Herr Iwan! Wie geht es Ihnen?","it":"Buongiorno, signor Ivan! Come sta?","es_ar":"مساء الخير يا سيّد إيفان! كيف حالك؟","fr":"Bonjour, monsieur Ivan ! Comment allez-vous ?"},{"uk":"Мамо, я вже вдома!","ru":"Мама, я уже дома!","en":"Mum, I'm home already!","de":"Mama, ich bin schon zu Hause!","it":"Mamma, sono già a casa!","es_ar":"يا أمّي، لقد عدتُ إلى البيت!","fr":"Maman, je suis déjà à la maison !"},{"uk":"Друже, допоможи мені, будь ласка.","ru":"Друг, помоги мне, пожалуйста.","en":"My friend, help me, please.","de":"Mein Freund, hilf mir bitte.","it":"Amico, aiutami, per favore.","es_ar":"يا صديقي، ساعدني من فضلك.","fr":"Mon ami, aide-moi, s'il te plaît."}],"hints":{"ru":"Не обращайтесь именительным, как в русском: не «Іван!», а «Іване!»; не «мама!», а «мамо!». Помните чередование г/к/х перед -е: друг → друже, Олег → Олеже, козак → козаче. Имя и фамилия/отчество оба ставятся в звательный: пане Іване.","en":"Don't address people with the nominative — Ukrainian needs the real vocative: «Іване!», «мамо!», «пане!». Remember the consonant shift before -е: друг → друже, козак → козаче. When you address a name plus a title, both go into the vocative: пане Іване.","de":"Reden Sie niemanden mit dem Nominativ an — das Ukrainische verlangt den echten Vokativ: «Іване!», «мамо!», «пане!». Beachten Sie den Konsonantenwechsel vor -е: друг → друже, козак → козаче. Titel und Name stehen beide im Vokativ: пане Іване.","it":"Non usare il nominativo per rivolgerti a qualcuno: l'ucraino richiede il vero vocativo: «Іване!», «мамо!», «пане!». Ricorda l'alternanza prima di -е: друг → друже, козак → козаче. Titolo e nome vanno entrambi al vocativo: пане Іване.","es_ar":"لا تنادِ الناس بحالة الرفع؛ تتطلّب الأوكرانية حالة النداء الحقيقية: «Іване!»، «мамо!»، «пане!». وتذكّر التبادل قبل -е: друг → друже، козак → козаче. اللقب والاسم كلاهما في حالة النداء: пане Іване.","fr":"N'interpellez pas les gens au nominatif : l'ukrainien exige le vrai vocatif : «Іване!», «мамо!», «пане!». Retenez l'alternance devant -е : друг → друже, козак → козаче. Le titre et le prénom se mettent tous deux au vocatif : пане Іване."}},
{"id":"past-tense","icon":"⏪","level":"A2","title":{"uk":"Минулий час","ru":"Прошедшее время","en":"Past tense","de":"Vergangenheit (Präteritum)","it":"Passato","es_ar":"الزمن الماضي","fr":"Passé"},"intro":{"uk":"Минулий час утворюється від основи інфінітива за допомогою суфікса -в/-л- та закінчень роду й числа. Чоловічий рід бере -в (читати → читав, робити → робив), жіночий -ла (читала, робила), середній -ло (читало), множина -ли (читали). Дієслово в минулому часі не змінюється за особами — тільки за родом (в однині) і числом. Тому «я читав» (чоловік) і «я читала» (жінка) відрізняються лише родом.","ru":"Прошедшее время образуется от основы инфинитива суффиксом -в/-л- и родовыми окончаниями. Важное отличие от русского: в мужском роде -в, а не -л: читав (не «читал»), робив, ходив. Женский -ла (читала), средний -ло (читало), множина -ли (читали). По лицам глагол в прошедшем НЕ изменяется — только по роду (в ед.ч.) и числу.","en":"The past tense is built from the infinitive stem plus the suffix -в/-л- and gender/number endings. Masculine takes -в (читати → читав, робити → робив), feminine -ла (читала), neuter -ло (читало), plural -ли (читали). Crucially, the past does NOT change by person — only by gender (in the singular) and number. So «я читав» (a man) and «я читала» (a woman) differ only in gender.","de":"Die Vergangenheit wird vom Infinitivstamm mit dem Suffix -в/-л- und Genus-/Numerus-Endungen gebildet. Maskulin nimmt -в (читати → читав, робити → робив), feminin -ла (читала), neutrum -ло (читало), Plural -ли (читали). Wichtig: Das Präteritum ändert sich NICHT nach Person — nur nach Genus (im Singular) und Numerus. So unterscheiden sich «я читав» (ein Mann) und «я читала» (eine Frau) nur im Genus.","it":"Il passato si forma dal tema dell'infinito con il suffisso -в/-л- e le desinenze di genere/numero. Il maschile prende -в (читати → читав, робити → робив), il femminile -ла (читала), il neutro -ло (читало), il plurale -ли (читали). Fondamentale: il passato NON cambia per persona, ma solo per genere (al singolare) e numero. Così «я читав» (un uomo) e «я читала» (una donna) differiscono solo nel genere.","es_ar":"يتكوّن الماضي من جذر المصدر بإضافة اللاحقة -в/-л- ونهايات الجنس والعدد. المذكّر يأخذ -в (читати → читав، робити → робив)، والمؤنّث -ла (читала)، والمحايد -ло (читало)، والجمع -ли (читали). والأهم: الفعل الماضي لا يتغيّر حسب الشخص، بل حسب الجنس (في المفرد) والعدد فقط. فـ«я читав» (رجل) و«я читала» (امرأة) يختلفان في الجنس فقط.","fr":"Le passé se forme sur le radical de l'infinitif avec le suffixe -в/-л- et les terminaisons de genre/nombre. Le masculin prend -в (читати → читав, робити → робив), le féminin -ла (читала), le neutre -ло (читало), le pluriel -ли (читали). Essentiel : le passé ne varie PAS selon la personne, mais seulement selon le genre (au singulier) et le nombre. Ainsi «я читав» (un homme) et «я читала» (une femme) ne diffèrent que par le genre."},"tables":[{"caption":{"uk":"Минулий час: читати і робити","ru":"Прошедшее время: читати и робити","en":"Past tense: читати & робити","de":"Vergangenheit: читати & робити","it":"Passato: читати e робити","es_ar":"الماضي: читати وробити","fr":"Passé : читати et робити"},"labelHeader":{"uk":"Рід / число","ru":"Род / число","en":"Gender / number","de":"Genus / Numerus","it":"Genere / numero","es_ar":"الجنس / العدد","fr":"Genre / nombre"},"columns":[{"uk":"читати","ru":"читати","en":"читати","de":"читати","it":"читати","es_ar":"читати","fr":"читати"},{"uk":"робити","ru":"робити","en":"робити","de":"робити","it":"робити","es_ar":"робити","fr":"робити"}],"rows":[{"label":{"uk":"чоловічий (він)","ru":"мужской (він)","en":"masculine (він)","de":"maskulin (він)","it":"maschile (він)","es_ar":"مذكّر (він)","fr":"masculin (він)"},"cells":["читав","робив"]},{"label":{"uk":"жіночий (вона)","ru":"женский (вона)","en":"feminine (вона)","de":"feminin (вона)","it":"femminile (вона)","es_ar":"مؤنّث (вона)","fr":"féminin (вона)"},"cells":["читала","робила"]},{"label":{"uk":"середній (воно)","ru":"средний (воно)","en":"neuter (воно)","de":"neutrum (воно)","it":"neutro (воно)","es_ar":"محايد (воно)","fr":"neutre (воно)"},"cells":["читало","робило"]},{"label":{"uk":"множина (ми/ви/вони)","ru":"множ. (ми/ви/вони)","en":"plural (ми/ви/вони)","de":"Plural (ми/ви/вони)","it":"plurale (ми/ви/вони)","es_ar":"جمع (ми/ви/вони)","fr":"pluriel (ми/ви/вони)"},"cells":["читали","робили"]}]}],"examples":[{"uk":"Учора я читав цікаву книгу цілий вечір.","ru":"Вчера я читал интересную книгу весь вечер.","en":"Yesterday I read an interesting book all evening.","de":"Gestern habe ich den ganzen Abend ein interessantes Buch gelesen.","it":"Ieri ho letto un libro interessante tutta la sera.","es_ar":"أمس قرأتُ كتابًا ممتعًا طوال المساء.","fr":"Hier, j'ai lu un livre intéressant toute la soirée."},{"uk":"Вона працювала в лікарні багато років.","ru":"Она работала в больнице много лет.","en":"She worked at the hospital for many years.","de":"Sie hat viele Jahre im Krankenhaus gearbeitet.","it":"Ha lavorato in ospedale per molti anni.","es_ar":"عملَت في المستشفى سنواتٍ كثيرة.","fr":"Elle a travaillé à l'hôpital pendant de nombreuses années."},{"uk":"Ми були в кіно і дивилися новий фільм.","ru":"Мы были в кино и смотрели новый фильм.","en":"We were at the cinema and watched a new film.","de":"Wir waren im Kino und haben einen neuen Film gesehen.","it":"Siamo stati al cinema e abbiamo visto un nuovo film.","es_ar":"كنّا في السينما وشاهدنا فيلمًا جديدًا.","fr":"Nous étions au cinéma et nous avons regardé un nouveau film."}],"hints":{"ru":"Главное: в мужском роде -в, а не -л, как в русском: читав, робив, ходив, писав (по-русски «читал»). Не изменяйте глагол по лицам — «я читав», «ти читав», «він читав» одинаковы; меняется только род и число. Женщина о себе говорит «я читала», «я була».","en":"The key trap: masculine past ends in -в, not -л — читав, робив, ходив, писав. The verb does not agree with person: «я читав», «ти читав», «він читав» are identical; only gender and number change. A woman says «я читала», «я була» about herself.","de":"Die wichtigste Falle: Der Maskulinum endet auf -в, nicht auf -л — читав, робив, ходив, писав. Das Verb kongruiert nicht mit der Person: «я читав», «ти читав», «він читав» sind gleich; nur Genus und Numerus ändern sich. Eine Frau sagt «я читала», «я була» über sich.","it":"La trappola principale: il maschile finisce in -в, non in -л — читав, робив, ходив, писав. Il verbo non concorda con la persona: «я читав», «ти читав», «він читав» sono identici; cambiano solo genere e numero. Una donna dice «я читала», «я була» di sé.","es_ar":"الفخّ الأساسي: المذكّر ينتهي بـ -в لا بـ -л — читав، робив، ходив، писав. الفعل لا يطابق الشخص: «я читав»، «ти читав»، «він читав» متطابقة؛ يتغيّر الجنس والعدد فقط. المرأة تقول عن نفسها «я читала»، «я була».","fr":"Le piège principal : le masculin se termine en -в, non en -л — читав, робив, ходив, писав. Le verbe ne s'accorde pas avec la personne : «я читав», «ти читав», «він читав» sont identiques ; seuls le genre et le nombre changent. Une femme dit «я читала», «я була» en parlant d'elle."}},
{"id":"future-tense","icon":"⏩","level":"A2","title":{"uk":"Майбутній час (три форми)","ru":"Будущее время (три формы)","en":"Future tense (three forms)","de":"Zukunft (drei Formen)","it":"Futuro (tre forme)","es_ar":"زمن المستقبل (ثلاث صيغ)","fr":"Futur (trois formes)"},"intro":{"uk":"Українська має три способи виразити майбутнє. Для недоконаного виду (процес): 1) складена форма «буду + інфінітив» (буду читати); 2) синтетична форма з -му (читатиму, читатимеш) — вона утворюється додаванням -му, -меш, -ме… прямо до інфінітива. Для доконаного виду (результат) є 3) проста форма, що відмінюється як теперішній час (прочитаю, прочитаєш). «Буду читати» і «читатиму» — це те саме значення, просто дві рівноправні форми.","ru":"В украинском три способа выразить будущее. Для несовершенного вида: 1) составное «буду + инфинитив» (буду читати); 2) синтетическая форма на -му (читатиму, читатимеш) — окончания -му/-меш/-ме… приклеиваются прямо к инфинитиву; такой формы в русском нет! Для совершенного вида 3) простая форма, спрягается как настоящее (прочитаю). «Буду читати» = «читатиму» — одно значение, две равноправные формы.","en":"Ukrainian has three ways to express the future. For the imperfective (process): 1) the compound «буду + infinitive» (буду читати); 2) a synthetic form in -му (читатиму, читатимеш) — the endings -му, -меш, -ме… attach straight onto the infinitive. For the perfective (result): 3) a simple form conjugated just like the present (прочитаю, прочитаєш). «Буду читати» and «читатиму» mean exactly the same — two equally correct forms.","de":"Das Ukrainische hat drei Wege für die Zukunft. Für den unvollendeten Aspekt (Prozess): 1) die zusammengesetzte Form «буду + Infinitiv» (буду читати); 2) eine synthetische Form auf -му (читатиму, читатимеш) — die Endungen -му, -меш, -ме… treten direkt an den Infinitiv. Für den vollendeten Aspekt (Ergebnis): 3) eine einfache Form, die wie das Präsens konjugiert wird (прочитаю). «Буду читати» und «читатиму» bedeuten genau dasselbe — zwei gleichwertige Formen.","it":"L'ucraino ha tre modi per esprimere il futuro. Per l'imperfettivo (processo): 1) la forma composta «буду + infinito» (буду читати); 2) una forma sintetica in -му (читатиму, читатимеш) — le desinenze -му, -меш, -ме… si attaccano direttamente all'infinito. Per il perfettivo (risultato): 3) una forma semplice coniugata come il presente (прочитаю). «Буду читати» e «читатиму» hanno lo stesso significato — due forme equivalenti.","es_ar":"للأوكرانية ثلاث طرق للتعبير عن المستقبل. للفعل غير التامّ (السيرورة): 1) الصيغة المركّبة «буду + المصدر» (буду читати)؛ 2) صيغة تركيبية على -му (читатиму، читатимеш) — تُلصق النهايات -му، -меш، -ме… مباشرةً بالمصدر. وللفعل التامّ (النتيجة): 3) صيغة بسيطة تُصرَّف كالمضارع (прочитаю). «буду читати» و«читатиму» لهما المعنى نفسه — صيغتان متكافئتان.","fr":"L'ukrainien a trois façons d'exprimer le futur. Pour l'imperfectif (processus) : 1) la forme composée «буду + infinitif» (буду читати) ; 2) une forme synthétique en -му (читатиму, читатимеш) — les terminaisons -му, -меш, -ме… se soudent directement à l'infinitif. Pour le perfectif (résultat) : 3) une forme simple conjuguée comme le présent (прочитаю). «буду читати» et «читатиму» ont exactement le même sens — deux formes équivalentes."},"tables":[{"caption":{"uk":"Недоконаний вид: дві форми майбутнього (читати)","ru":"Несовершенный вид: две формы будущего (читати)","en":"Imperfective: two future forms (читати)","de":"Unvollendet: zwei Zukunftsformen (читати)","it":"Imperfettivo: due forme di futuro (читати)","es_ar":"غير التامّ: صيغتا المستقبل (читати)","fr":"Imperfectif : deux formes de futur (читати)"},"labelHeader":{"uk":"Особа","ru":"Лицо","en":"Person","de":"Person","it":"Persona","es_ar":"الشخص","fr":"Personne"},"columns":[{"uk":"буду + інфінітив","ru":"буду + инфинитив","en":"буду + infinitive","de":"буду + Infinitiv","it":"буду + infinito","es_ar":"буду + المصدر","fr":"буду + infinitif"},{"uk":"синтетична (-му)","ru":"синтетическая (-му)","en":"synthetic (-му)","de":"synthetisch (-му)","it":"sintetica (-му)","es_ar":"التركيبية (-му)","fr":"synthétique (-му)"}],"rows":[{"label":{"uk":"я","ru":"я","en":"я","de":"я","it":"я","es_ar":"я","fr":"я"},"cells":["буду читати","читатиму"]},{"label":{"uk":"ти","ru":"ти","en":"ти","de":"ти","it":"ти","es_ar":"ти","fr":"ти"},"cells":["будеш читати","читатимеш"]},{"label":{"uk":"він/вона/воно","ru":"він/вона/воно","en":"він/вона/воно","de":"він/вона/воно","it":"він/вона/воно","es_ar":"він/вона/воно","fr":"він/вона/воно"},"cells":["буде читати","читатиме"]},{"label":{"uk":"ми","ru":"ми","en":"ми","de":"ми","it":"ми","es_ar":"ми","fr":"ми"},"cells":["будемо читати","читатимемо"]},{"label":{"uk":"ви","ru":"ви","en":"ви","de":"ви","it":"ви","es_ar":"ви","fr":"ви"},"cells":["будете читати","читатимете"]},{"label":{"uk":"вони","ru":"вони","en":"вони","de":"вони","it":"вони","es_ar":"вони","fr":"вони"},"cells":["будуть читати","читатимуть"]}]},{"caption":{"uk":"Доконаний вид: проста форма (прочитати)","ru":"Совершенный вид: простая форма (прочитати)","en":"Perfective: simple form (прочитати)","de":"Vollendet: einfache Form (прочитати)","it":"Perfettivo: forma semplice (прочитати)","es_ar":"التامّ: الصيغة البسيطة (прочитати)","fr":"Perfectif : forme simple (прочитати)"},"labelHeader":{"uk":"Особа","ru":"Лицо","en":"Person","de":"Person","it":"Persona","es_ar":"الشخص","fr":"Personne"},"columns":[{"uk":"прочитати (док.)","ru":"прочитати (сов.)","en":"прочитати (perf.)","de":"прочитати (vollend.)","it":"прочитати (perf.)","es_ar":"прочитати (تامّ)","fr":"прочитати (perf.)"}],"rows":[{"label":{"uk":"я","ru":"я","en":"я","de":"я","it":"я","es_ar":"я","fr":"я"},"cells":["прочитаю"]},{"label":{"uk":"ти","ru":"ти","en":"ти","de":"ти","it":"ти","es_ar":"ти","fr":"ти"},"cells":["прочитаєш"]},{"label":{"uk":"він/вона/воно","ru":"він/вона/воно","en":"він/вона/воно","de":"він/вона/воно","it":"він/вона/воно","es_ar":"він/вона/воно","fr":"він/вона/воно"},"cells":["прочитає"]},{"label":{"uk":"ми","ru":"ми","en":"ми","de":"ми","it":"ми","es_ar":"ми","fr":"ми"},"cells":["прочитаємо"]},{"label":{"uk":"ви","ru":"ви","en":"ви","de":"ви","it":"ви","es_ar":"ви","fr":"ви"},"cells":["прочитаєте"]},{"label":{"uk":"вони","ru":"вони","en":"вони","de":"вони","it":"вони","es_ar":"вони","fr":"вони"},"cells":["прочитають"]}]}],"examples":[{"uk":"Завтра я буду відпочивати, або: завтра я відпочиватиму.","ru":"Завтра я буду отдыхать, или: завтра я отдохну (укр. відпочиватиму).","en":"Tomorrow I will rest — either «буду відпочивати» or «відпочиватиму».","de":"Morgen werde ich mich ausruhen — entweder «буду відпочивати» oder «відпочиватиму».","it":"Domani mi riposerò — «буду відпочивати» oppure «відпочиватиму».","es_ar":"غدًا سأرتاح — إمّا «буду відпочивати» أو «відпочиватиму».","fr":"Demain je me reposerai — soit «буду відпочивати», soit «відпочиватиму»."},{"uk":"Ми прочитаємо цю книгу за тиждень.","ru":"Мы прочитаем эту книгу за неделю.","en":"We will read this book in a week.","de":"Wir werden dieses Buch in einer Woche lesen.","it":"Leggeremo questo libro in una settimana.","es_ar":"سنقرأ هذا الكتاب خلال أسبوع.","fr":"Nous lirons ce livre en une semaine."},{"uk":"Що ти робитимеш увечері?","ru":"Что ты будешь делать вечером?","en":"What will you be doing this evening?","de":"Was wirst du heute Abend machen?","it":"Cosa farai stasera?","es_ar":"ماذا ستفعل هذا المساء؟","fr":"Que feras-tu ce soir ?"}],"hints":{"ru":"Синтетическая форма на -му (читатиму, робитиму) — чисто украинская, в русском её нет; это удобный «слитный» способ вместо «буду + инфинитив». Не путайте виды: у совершенного вида НЕТ настоящего времени, «прочитаю» — это уже будущее. Несовершенный: два варианта на выбор, оба верны.","en":"The synthetic -му form (читатиму, робитиму) is distinctly Ukrainian — a neat one-word alternative to «буду + infinitive». Keep aspects straight: a perfective verb has NO present, so «прочитаю» is already future. Imperfective offers two options, both correct.","de":"Die synthetische -му-Form (читатиму, робитиму) ist typisch ukrainisch — eine kompakte Ein-Wort-Alternative zu «буду + Infinitiv». Beachten Sie den Aspekt: Ein vollendetes Verb hat KEIN Präsens, «прочитаю» ist bereits Zukunft. Der unvollendete Aspekt bietet zwei gleichwertige Formen.","it":"La forma sintetica in -му (читатиму, робитиму) è tipicamente ucraina — una comoda alternativa in una parola a «буду + infinito». Attenzione all'aspetto: un verbo perfettivo NON ha presente, quindi «прочитаю» è già futuro. L'imperfettivo offre due opzioni, entrambe corrette.","es_ar":"الصيغة التركيبية على -му (читатиму، робитиму) أوكرانية مميّزة — بديل من كلمة واحدة عن «буду + المصدر». انتبه للجهة: الفعل التامّ لا مضارع له، فـ«прочитаю» مستقبلٌ أصلًا. وغير التامّ يتيح خيارين، وكلاهما صحيح.","fr":"La forme synthétique en -му (читатиму, робитиму) est typiquement ukrainienne — une alternative en un mot à «буду + infinitif». Gardez l'aspect clair : un verbe perfectif n'a PAS de présent, donc «прочитаю» est déjà un futur. L'imperfectif offre deux options, toutes deux correctes."}},
{"id":"verb-aspect","icon":"🔁","level":"A2","title":{"uk":"Вид дієслова (недоконаний / доконаний)","ru":"Вид глагола (несовершенный / совершенный)","en":"Verb aspect (imperfective / perfective)","de":"Verbaspekt (unvollendet / vollendet)","it":"Aspetto del verbo (imperfettivo / perfettivo)","es_ar":"جهة الفعل (غير التامّ / التامّ)","fr":"Aspect verbal (imperfectif / perfectif)"},"intro":{"uk":"Майже кожне дієслово існує у двох видах. Недоконаний вид описує процес, повторення чи тривалість (читати, писати, робити) і має всі три часи. Доконаний вид описує завершену дію з результатом (прочитати, написати, зробити) і має лише минулий і майбутній час — теперішнього в нього немає. Видову пару найчастіше творять префіксом (писати → написати), суфіксом (купувати → купити) або зовсім іншим коренем (брати → взяти, говорити → сказати).","ru":"Как и в русском, почти каждый глагол имеет два вида. Несовершенный — процесс, повторение, длительность (читати, писати) — есть во всех трёх временах. Совершенный — завершённое действие с результатом (прочитати, написати) — только прошедшее и будущее, настоящего у него НЕТ. Видовую пару образуют приставкой (писати → написати), суффиксом (купувати → купити) или другим корнем (брати → взяти).","en":"Almost every verb comes in two aspects. The imperfective describes a process, repetition, or duration (читати, писати, робити) and exists in all three tenses. The perfective describes a single completed action with a result (прочитати, написати, зробити) and has only past and future — no present at all. Aspect pairs are formed by a prefix (писати → написати), a suffix (купувати → купити), or a different root (брати → взяти, говорити → сказати).","de":"Fast jedes Verb tritt in zwei Aspekten auf. Der unvollendete Aspekt beschreibt einen Prozess, eine Wiederholung oder Dauer (читати, писати, робити) und existiert in allen drei Zeiten. Der vollendete Aspekt beschreibt eine abgeschlossene Handlung mit Ergebnis (прочитати, написати, зробити) und hat nur Vergangenheit und Zukunft — gar kein Präsens. Aspektpaare bildet man durch ein Präfix (писати → написати), ein Suffix (купувати → купити) oder eine andere Wurzel (брати → взяти).","it":"Quasi ogni verbo esiste in due aspetti. L'imperfettivo descrive un processo, una ripetizione o una durata (читати, писати, робити) ed esiste in tutti e tre i tempi. Il perfettivo descrive un'azione compiuta con un risultato (прочитати, написати, зробити) e ha solo passato e futuro — nessun presente. Le coppie aspettuali si formano con un prefisso (писати → написати), un suffisso (купувати → купити) o una radice diversa (брати → взяти).","es_ar":"يوجد كل فعل تقريبًا في جهتين. غير التامّ يصف سيرورةً أو تكرارًا أو مدّة (читати، писати، робити) ويوجد في الأزمنة الثلاثة. والتامّ يصف فعلًا مكتملًا بنتيجة (прочитати، написати، зробити) وله الماضي والمستقبل فقط — لا مضارع له البتّة. وتُكوَّن أزواج الجهة بسابقة (писати → написати) أو لاحقة (купувати → купити) أو جذر مختلف (брати → взяти).","fr":"Presque chaque verbe existe sous deux aspects. L'imperfectif décrit un processus, une répétition ou une durée (читати, писати, робити) et existe aux trois temps. Le perfectif décrit une action achevée avec un résultat (прочитати, написати, зробити) et n'a que le passé et le futur — aucun présent. Les paires d'aspect se forment par un préfixe (писати → написати), un suffixe (купувати → купити) ou une racine différente (брати → взяти)."},"tables":[{"caption":{"uk":"Видові пари та способи їх творення","ru":"Видовые пары и способы их образования","en":"Aspect pairs and how they are formed","de":"Aspektpaare und ihre Bildung","it":"Coppie aspettuali e loro formazione","es_ar":"أزواج الجهة وطرق تكوينها","fr":"Paires d'aspect et leur formation"},"labelHeader":{"uk":"Спосіб творення","ru":"Способ образования","en":"Formation","de":"Bildung","it":"Formazione","es_ar":"طريقة التكوين","fr":"Formation"},"columns":[{"uk":"Недоконаний","ru":"Несовершенный","en":"Imperfective","de":"Unvollendet","it":"Imperfettivo","es_ar":"غير التامّ","fr":"Imperfectif"},{"uk":"Доконаний","ru":"Совершенный","en":"Perfective","de":"Vollendet","it":"Perfettivo","es_ar":"التامّ","fr":"Perfectif"}],"rows":[{"label":{"uk":"префікс на-","ru":"приставка на-","en":"prefix на-","de":"Präfix на-","it":"prefisso на-","es_ar":"سابقة на-","fr":"préfixe на-"},"cells":["писати","написати"]},{"label":{"uk":"префікс про-","ru":"приставка про-","en":"prefix про-","de":"Präfix про-","it":"prefisso про-","es_ar":"سابقة про-","fr":"préfixe про-"},"cells":["читати","прочитати"]},{"label":{"uk":"префікс з-/зро-","ru":"приставка з-/зро-","en":"prefix з-/зро-","de":"Präfix з-/зро-","it":"prefisso з-/зро-","es_ar":"سابقة з-/зро-","fr":"préfixe з-/зро-"},"cells":["робити","зробити"]},{"label":{"uk":"зміна суфікса","ru":"смена суффикса","en":"suffix change","de":"Suffixwechsel","it":"cambio di suffisso","es_ar":"تغيير اللاحقة","fr":"changement de suffixe"},"cells":["купувати","купити"]},{"label":{"uk":"різні корені","ru":"разные корни","en":"different roots","de":"verschiedene Wurzeln","it":"radici diverse","es_ar":"جذور مختلفة","fr":"racines différentes"},"cells":["брати","взяти"]},{"label":{"uk":"різні корені","ru":"разные корни","en":"different roots","de":"verschiedene Wurzeln","it":"radici diverse","es_ar":"جذور مختلفة","fr":"racines différentes"},"cells":["говорити","сказати"]}]}],"examples":[{"uk":"Я писав листа цілу годину, і нарешті написав його.","ru":"Я писал письмо целый час и наконец написал его.","en":"I was writing the letter for a whole hour and finally finished it.","de":"Ich schrieb eine ganze Stunde an dem Brief und habe ihn schließlich fertig geschrieben.","it":"Ho scritto la lettera per un'ora intera e alla fine l'ho finita.","es_ar":"كتبتُ الرسالة ساعةً كاملة وأنهيتُها أخيرًا.","fr":"J'ai écrit la lettre pendant une heure entière et je l'ai enfin terminée."},{"uk":"Щодня я читаю, і сьогодні вже прочитав цілий розділ.","ru":"Каждый день я читаю, и сегодня уже прочитал целую главу.","en":"Every day I read, and today I have already finished a whole chapter.","de":"Jeden Tag lese ich, und heute habe ich schon ein ganzes Kapitel gelesen.","it":"Ogni giorno leggo, e oggi ho già finito un intero capitolo.","es_ar":"أقرأ كل يوم، واليوم أنهيتُ فصلًا كاملًا بالفعل.","fr":"Chaque jour je lis, et aujourd'hui j'ai déjà terminé un chapitre entier."},{"uk":"Вона довго вибирала сукню і нарешті купила її.","ru":"Она долго выбирала платье и наконец купила его.","en":"She spent a long time choosing a dress and finally bought it.","de":"Sie hat lange ein Kleid ausgesucht und es schließlich gekauft.","it":"Ha scelto a lungo un vestito e alla fine l'ha comprato.","es_ar":"اختارت الفستان طويلًا ثم اشترته أخيرًا.","fr":"Elle a longtemps choisi une robe et l'a finalement achetée."}],"hints":{"ru":"Ключевое: у совершенного вида НЕТ настоящего времени. «Прочитаю» — это будущее, а не «читаю сейчас». Процесс и повторение → несовершенный (читаю, читав, буду читати); результат «сделал/сделаю» → совершенный (прочитав, прочитаю). Учите глаголы сразу парами: писати/написати.","en":"The core rule: a perfective verb has NO present tense. «Прочитаю» is future ('I will read/finish'), never 'I read now'. Process and repetition → imperfective (читаю, читав, буду читати); a completed result → perfective (прочитав, прочитаю). Learn verbs in pairs: писати/написати.","de":"Die Kernregel: Ein vollendetes Verb hat KEIN Präsens. «Прочитаю» ist Zukunft ('ich werde lesen'), nie 'ich lese jetzt'. Prozess und Wiederholung → unvollendet (читаю, читав, буду читати); ein abgeschlossenes Ergebnis → vollendet (прочитав, прочитаю). Lernen Sie Verben paarweise: писати/написати.","it":"La regola chiave: un verbo perfettivo NON ha il presente. «Прочитаю» è futuro ('leggerò/finirò'), mai 'leggo ora'. Processo e ripetizione → imperfettivo (читаю, читав, буду читати); un risultato compiuto → perfettivo (прочитав, прочитаю). Impara i verbi a coppie: писати/написати.","es_ar":"القاعدة الجوهرية: الفعل التامّ لا مضارع له. «прочитаю» مستقبلٌ ('سأقرأ/سأُنهي') لا 'أقرأ الآن'. السيرورة والتكرار ← غير التامّ (читаю، читав، буду читати)؛ والنتيجة المكتملة ← التامّ (прочитав، прочитаю). احفظ الأفعال أزواجًا: писати/написати.","fr":"La règle centrale : un verbe perfectif n'a PAS de présent. «Прочитаю» est un futur ('je lirai/finirai'), jamais 'je lis maintenant'. Processus et répétition → imperfectif (читаю, читав, буду читати) ; un résultat achevé → perfectif (прочитав, прочитаю). Apprenez les verbes par paires : писати/написати."}},
{"id":"adjective-agreement","icon":"🎨","level":"A2","title":{"uk":"Узгодження прикметників (тверда і м'яка групи)","ru":"Согласование прилагательных (твёрдая и мягкая группы)","en":"Adjective agreement (hard & soft groups)","de":"Adjektivkongruenz (harte & weiche Gruppe)","it":"Accordo dell'aggettivo (gruppo duro e molle)","es_ar":"مطابقة الصفة (المجموعتان الصلبة واللينة)","fr":"Accord de l'adjectif (groupes dur et mou)"},"intro":{"uk":"Прикметник узгоджується з іменником у роді, числі й відмінку і зазвичай стоїть перед ним. Прикметники поділяються на дві групи. Тверда група має закінчення -ий (чол.), -а (жін.), -е (сер.), -і (мн.): новий, нова, нове, нові. М'яка група закінчується на -ій (чол.), -я (жін.), -є (сер.), -і (мн.): синій, синя, синє, сині. До м'якої групи належать прикметники на -ній (давній, ранній, останній) та кілька інших (синій, безкраїй).","ru":"Прилагательное согласуется с существительным в роде, числе и падеже и обычно стоит перед ним. Две группы. Твёрдая: -ий (муж.), -а (жен.), -е (ср.), -і (мн.): новий, нова, нове, нові. Обратите внимание: муж. -ий и мн. -і, а не -ый/-ые, как в русском. Мягкая: -ій, -я, -є, -і: синій, синя, синє, сині — сюда входят прилагательные на -ній (давній, останній).","en":"An adjective agrees with its noun in gender, number, and case, and normally stands before it. Adjectives fall into two groups. The hard group ends in -ий (masc.), -а (fem.), -е (neut.), -і (plur.): новий, нова, нове, нові. The soft group ends in -ій (masc.), -я (fem.), -є (neut.), -і (plur.): синій, синя, синє, сині. The soft group includes adjectives in -ній (давній, ранній, останній) and a few others (синій, безкраїй).","de":"Ein Adjektiv kongruiert mit dem Nomen in Genus, Numerus und Kasus und steht meist davor. Es gibt zwei Gruppen. Die harte Gruppe endet auf -ий (mask.), -а (fem.), -е (neut.), -і (Pl.): новий, нова, нове, нові. Die weiche Gruppe endet auf -ій (mask.), -я (fem.), -є (neut.), -і (Pl.): синій, синя, синє, сині. Zur weichen Gruppe gehören Adjektive auf -ній (давній, ранній, останній) und einige weitere (синій, безкраїй).","it":"L'aggettivo concorda con il nome in genere, numero e caso e di solito lo precede. Ci sono due gruppi. Il gruppo duro finisce in -ий (masch.), -а (femm.), -е (neut.), -і (plur.): новий, нова, нове, нові. Il gruppo molle finisce in -ій (masch.), -я (femm.), -є (neut.), -і (plur.): синій, синя, синє, сині. Al gruppo molle appartengono gli aggettivi in -ній (давній, ранній, останній) e alcuni altri (синій, безкраїй).","es_ar":"تطابق الصفة الاسم في الجنس والعدد والحالة، وتسبقه عادةً. وهناك مجموعتان. الصلبة تنتهي بـ -ий (مذكّر)، -а (مؤنّث)، -е (محايد)، -і (جمع): новий، нова، нове، нові. واللينة تنتهي بـ -ій (مذكّر)، -я (مؤنّث)، -є (محايد)، -і (جمع): синій، синя، синє، сині. وتشمل اللينةَ الصفاتُ على -ній (давній، ранній، останній) وبعض غيرها (синій، безкраїй).","fr":"L'adjectif s'accorde avec le nom en genre, nombre et cas, et le précède généralement. Il y a deux groupes. Le groupe dur se termine en -ий (masc.), -а (fém.), -е (neut.), -і (plur.) : новий, нова, нове, нові. Le groupe mou se termine en -ій (masc.), -я (fém.), -є (neut.), -і (plur.) : синій, синя, синє, сині. Le groupe mou comprend les adjectifs en -ній (давній, ранній, останній) et quelques autres (синій, безкраїй)."},"tables":[{"caption":{"uk":"Закінчення прикметника за родом і числом (називний)","ru":"Окончания прилагательного по роду и числу (именительный)","en":"Adjective endings by gender and number (nominative)","de":"Adjektivendungen nach Genus und Numerus (Nominativ)","it":"Desinenze dell'aggettivo per genere e numero (nominativo)","es_ar":"نهايات الصفة حسب الجنس والعدد (حالة الرفع)","fr":"Terminaisons de l'adjectif par genre et nombre (nominatif)"},"labelHeader":{"uk":"Рід / число","ru":"Род / число","en":"Gender / number","de":"Genus / Numerus","it":"Genere / numero","es_ar":"الجنس / العدد","fr":"Genre / nombre"},"columns":[{"uk":"Тверда група (новий)","ru":"Твёрдая группа (новий)","en":"Hard group (новий)","de":"Harte Gruppe (новий)","it":"Gruppo duro (новий)","es_ar":"المجموعة الصلبة (новий)","fr":"Groupe dur (новий)"},{"uk":"М'яка група (синій)","ru":"Мягкая группа (синій)","en":"Soft group (синій)","de":"Weiche Gruppe (синій)","it":"Gruppo molle (синій)","es_ar":"المجموعة اللينة (синій)","fr":"Groupe mou (синій)"}],"rows":[{"label":{"uk":"чоловічий","ru":"мужской","en":"masculine","de":"maskulin","it":"maschile","es_ar":"مذكّر","fr":"masculin"},"cells":["новий","синій"]},{"label":{"uk":"жіночий","ru":"женский","en":"feminine","de":"feminin","it":"femminile","es_ar":"مؤنّث","fr":"féminin"},"cells":["нова","синя"]},{"label":{"uk":"середній","ru":"средний","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["нове","синє"]},{"label":{"uk":"множина","ru":"множина","en":"plural","de":"Plural","it":"plurale","es_ar":"جمع","fr":"pluriel"},"cells":["нові","сині"]}]}],"examples":[{"uk":"Це новий будинок, а поруч нова школа.","ru":"Это новый дом, а рядом новая школа.","en":"This is a new building, and next to it a new school.","de":"Das ist ein neues Haus, und daneben eine neue Schule.","it":"Questo è un edificio nuovo e accanto una scuola nuova.","es_ar":"هذا مبنًى جديد، وبجانبه مدرسة جديدة.","fr":"C'est un immeuble neuf, et à côté une école neuve."},{"uk":"Синє небо і сині очі.","ru":"Синее небо и синие глаза.","en":"A blue sky and blue eyes.","de":"Ein blauer Himmel und blaue Augen.","it":"Un cielo azzurro e occhi azzurri.","es_ar":"سماء زرقاء وعينان زرقاوان.","fr":"Un ciel bleu et des yeux bleus."},{"uk":"Гарні квіти стоять у великій вазі.","ru":"Красивые цветы стоят в большой вазе.","en":"Beautiful flowers stand in a large vase.","de":"Schöne Blumen stehen in einer großen Vase.","it":"Bei fiori sono in un grande vaso.","es_ar":"زهورٌ جميلة في مزهريّة كبيرة.","fr":"De belles fleurs sont dans un grand vase."}],"hints":{"ru":"Прилагательное всегда подстраивается под род, число и падеж существительного: новий стіл, нова книга, нове вікно, нові столи. Мужское -ий и множ. -і, а не русские -ый/-ые. Мягкая группа (синій, останній, ранній) даёт -ій/-я/-є/-і — не путайте синій (м.) и синя (ж.).","en":"An adjective always follows the noun's gender, number, and case: новий стіл, нова книга, нове вікно, нові столи. Masculine is -ий and plural -і (not English word order clues — the ending does the work). The soft group (синій, останній, ранній) gives -ій/-я/-є/-і — keep синій (m.) apart from синя (f.).","de":"Das Adjektiv richtet sich immer nach Genus, Numerus und Kasus des Nomens: новий стіл, нова книга, нове вікно, нові столи. Maskulin ist -ий, Plural -і. Die weiche Gruppe (синій, останній, ранній) ergibt -ій/-я/-є/-і — halten Sie синій (m.) und синя (f.) auseinander.","it":"L'aggettivo segue sempre genere, numero e caso del nome: новий стіл, нова книга, нове вікно, нові столи. Il maschile è -ий, il plurale -і. Il gruppo molle (синій, останній, ранній) dà -ій/-я/-є/-і — distingui синій (m.) da синя (f.).","es_ar":"تتبع الصفة دائمًا جنس الاسم وعدده وحالته: новий стіл، нова книга، нове вікно, нові столи. المذكّر -ий والجمع -і. والمجموعة اللينة (синій، останній، ранній) تعطي -ій/-я/-є/-і — ميّز синій (مذكّر) عن синя (مؤنّث).","fr":"L'adjectif suit toujours le genre, le nombre et le cas du nom : новий стіл, нова книга, нове вікно, нові столи. Le masculin est -ий, le pluriel -і. Le groupe mou (синій, останній, ранній) donne -ій/-я/-є/-і — distinguez синій (m.) de синя (f.)."}},
{"id":"prepositions-cases","icon":"🧭","level":"A2","title":{"uk":"Прийменники та відмінки","ru":"Предлоги и падежи","en":"Prepositions & cases","de":"Präpositionen & Kasus","it":"Preposizioni e casi","es_ar":"حروف الجرّ والحالات","fr":"Prépositions et cas"},"intro":{"uk":"Кожен прийменник вимагає певного відмінка іменника (керує ним). Місце (де?) виражають прийменники у/в, на з місцевим відмінком: у місті, на столі. Напрямок (куди?) — ті самі у/в, на, але зі знахідним: у місто, на стіл. Прийменники з (звідки?), до, від, біля вимагають родового: з роботи, до школи. Прийменник з у значенні «разом» бере орудний: з другом. Прийменники над, під, за, перед, між теж керують орудним: над столом, під деревом.","ru":"Каждый предлог требует определённого падежа (управляет им). Место (где?) — у/в, на с местным (предложным) падежом: у місті, на столі. Направление (куда?) — те же у/в, на, но с винительным: у місто, на стіл. Предлоги з (откуда?), до, від, біля требуют родительного: з роботи, до школи. Предлог з в значении «вместе с» — орудный (творительный): з другом. Над, під, за, перед, між — тоже орудный: над столом.","en":"Every preposition requires (governs) a particular case. Location (where?) is expressed by у/в and на with the locative: у місті, на столі. Direction (where to?) uses the same у/в, на but with the accusative: у місто, на стіл. The prepositions з (from), до, від, біля take the genitive: з роботи, до школи. The preposition з meaning 'together with' takes the instrumental: з другом. The prepositions над, під, за, перед, між also govern the instrumental: над столом, під деревом.","de":"Jede Präposition verlangt (regiert) einen bestimmten Kasus. Der Ort (wo?) wird mit у/в und на plus Lokativ ausgedrückt: у місті, на столі. Die Richtung (wohin?) verwendet dieselben у/в, на, aber mit dem Akkusativ: у місто, на стіл. Die Präpositionen з (von), до, від, біля stehen mit dem Genitiv: з роботи, до школи. Das з im Sinne von 'zusammen mit' steht mit dem Instrumental: з другом. Auch над, під, за, перед, між regieren den Instrumental: над столом.","it":"Ogni preposizione richiede (regge) un caso preciso. Il luogo (dove?) si esprime con у/в e на più il locativo: у місті, на столі. La direzione (dove?) usa gli stessi у/в, на ma con l'accusativo: у місто, на стіл. Le preposizioni з (da), до, від, біля reggono il genitivo: з роботи, до школи. La з nel senso di 'insieme a' regge lo strumentale: з другом. Anche над, під, за, перед, між reggono lo strumentale: над столом.","es_ar":"كل حرف جرّ يتطلّب (يحكم) حالةً معيّنة. المكان (أين؟) يُعبَّر عنه بـ у/в وна مع حالة المكان: у місті، на столі. والاتجاه (إلى أين؟) يستعمل у/в، на نفسها لكن مع حالة النصب: у місто، на стіл. وحروف з (من)، до، від، біля تتطلّب حالة الجرّ: з роботи، до школи. وحرف з بمعنى «مع» يأخذ حالة الآلة: з другом. وكذلك над، під، за، перед، між تحكم حالة الآلة: над столом.","fr":"Chaque préposition exige (régit) un cas précis. Le lieu (où ?) s'exprime avec у/в et на suivis du locatif : у місті, на столі. La direction (vers où ?) emploie les mêmes у/в, на mais avec l'accusatif : у місто, на стіл. Les prépositions з (de), до, від, біля régissent le génitif : з роботи, до школи. La préposition з au sens de « avec » régit l'instrumental : з другом. Les prépositions над, під, за, перед, між régissent aussi l'instrumental : над столом."},"tables":[{"caption":{"uk":"Прийменники та відмінки, якими вони керують","ru":"Предлоги и падежи, которыми они управляют","en":"Prepositions and the cases they govern","de":"Präpositionen und die von ihnen regierten Kasus","it":"Preposizioni e casi che reggono","es_ar":"حروف الجرّ والحالات التي تحكمها","fr":"Prépositions et les cas qu'elles régissent"},"labelHeader":{"uk":"Прийменник (значення)","ru":"Предлог (значение)","en":"Preposition (meaning)","de":"Präposition (Bedeutung)","it":"Preposizione (significato)","es_ar":"حرف الجرّ (المعنى)","fr":"Préposition (sens)"},"columns":[{"uk":"Відмінок","ru":"Падеж","en":"Case","de":"Kasus","it":"Caso","es_ar":"الحالة","fr":"Cas"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"у / в, на (де?)","ru":"у / в, на (где?)","en":"у / в, на (where?)","de":"у / в, на (wo?)","it":"у / в, на (dove?)","es_ar":"у / в، на (أين؟)","fr":"у / в, на (où ?)"},"cells":["місцевий","у місті, на столі"]},{"label":{"uk":"у / в, на (куди?)","ru":"у / в, на (куда?)","en":"у / в, на (where to?)","de":"у / в, на (wohin?)","it":"у / в, на (dove?)","es_ar":"у / в، на (إلى أين؟)","fr":"у / в, на (vers où ?)"},"cells":["знахідний","у місто, на стіл"]},{"label":{"uk":"з (звідки?)","ru":"з (откуда?)","en":"з (from)","de":"з (woher?)","it":"з (da)","es_ar":"з (من)","fr":"з (d'où ?)"},"cells":["родовий","з роботи, з міста"]},{"label":{"uk":"до, від, біля","ru":"до, від, біля","en":"до, від, біля","de":"до, від, біля","it":"до, від, біля","es_ar":"до، від، біля","fr":"до, від, біля"},"cells":["родовий","до школи, від друга, біля дому"]},{"label":{"uk":"з (з ким/чим?)","ru":"з (с кем/чем?)","en":"з (with)","de":"з (mit)","it":"з (con)","es_ar":"з (مع)","fr":"з (avec)"},"cells":["орудний","з другом, з молоком"]},{"label":{"uk":"над, під, за, перед","ru":"над, під, за, перед","en":"над, під, за, перед","de":"над, під, за, перед","it":"над, під, за, перед","es_ar":"над، під، за، перед","fr":"над, під, за, перед"},"cells":["орудний","над столом, під деревом"]},{"label":{"uk":"про (про що?)","ru":"про (о чём?)","en":"про (about)","de":"про (über)","it":"про (su)","es_ar":"про (عن)","fr":"про (au sujet de)"},"cells":["знахідний","про фільм, про подорож"]}]}],"examples":[{"uk":"Книга лежить на столі, а я кладу зошит на стіл.","ru":"Книга лежит на столе, а я кладу тетрадь на стол.","en":"The book is lying on the table, and I put the notebook onto the table.","de":"Das Buch liegt auf dem Tisch, und ich lege das Heft auf den Tisch.","it":"Il libro è sul tavolo e io metto il quaderno sul tavolo.","es_ar":"الكتاب على الطاولة، وأنا أضع الدفتر على الطاولة.","fr":"Le livre est sur la table, et je pose le cahier sur la table."},{"uk":"Ми йдемо до школи разом з друзями.","ru":"Мы идём в школу вместе с друзьями.","en":"We are going to school together with our friends.","de":"Wir gehen zusammen mit Freunden zur Schule.","it":"Andiamo a scuola insieme agli amici.","es_ar":"نذهب إلى المدرسة مع أصدقائنا.","fr":"Nous allons à l'école avec nos amis."},{"uk":"Розкажи мені про свою подорож до Львова.","ru":"Расскажи мне о своём путешествии во Львов.","en":"Tell me about your trip to Lviv.","de":"Erzähl mir von deiner Reise nach Lwiw.","it":"Raccontami del tuo viaggio a Leopoli.","es_ar":"احكِ لي عن رحلتك إلى لفيف.","fr":"Raconte-moi ton voyage à Lviv."}],"hints":{"ru":"Один и тот же предлог меняет падеж со смыслом: на столі (где? — местный) vs на стіл (куда? — винительный). Различайте два «з»: з роботи (откуда — родительный) и з другом (с кем — орудный). Учите предлог сразу с падежом: до + родительный, над/під/за + орудный.","en":"The same preposition switches case with meaning: на столі (where? — locative) vs на стіл (where to? — accusative). Distinguish the two з: з роботи (from — genitive) and з другом (with — instrumental). Learn each preposition together with its case: до + genitive, над/під/за + instrumental.","de":"Dieselbe Präposition wechselt den Kasus mit der Bedeutung: на столі (wo? — Lokativ) vs. на стіл (wohin? — Akkusativ). Unterscheiden Sie die zwei з: з роботи (woher — Genitiv) und з другом (mit — Instrumental). Lernen Sie jede Präposition mit ihrem Kasus: до + Genitiv, над/під/за + Instrumental.","it":"La stessa preposizione cambia caso col significato: на столі (dove? — locativo) vs на стіл (dove? — accusativo). Distingui i due з: з роботи (da — genitivo) e з другом (con — strumentale). Impara ogni preposizione col suo caso: до + genitivo, над/під/за + strumentale.","es_ar":"حرف الجرّ نفسه يغيّر الحالة بتغيّر المعنى: на столі (أين؟ — المكان) مقابل на стіл (إلى أين؟ — النصب). ميّز بين الـ з: з роботи (من — الجرّ) وз другом (مع — الآلة). احفظ كل حرف مع حالته: до + الجرّ، над/під/за + الآلة.","fr":"La même préposition change de cas selon le sens : на столі (où ? — locatif) vs на стіл (vers où ? — accusatif). Distinguez les deux з : з роботи (de — génitif) et з другом (avec — instrumental). Apprenez chaque préposition avec son cas : до + génitif, над/під/за + instrumental."}},
{"id":"instrumental-locative","icon":"🧰","level":"B1","title":{"uk":"Орудний та місцевий відмінки","ru":"Творительный и предложный падежи","en":"Instrumental & locative cases","de":"Instrumental und Lokativ","it":"Strumentale e locativo","es_ar":"حالتا الأداة والظرفية","fr":"Instrumental et locatif"},"intro":{"uk":"Орудний відмінок відповідає на питання «ким? чим?» і має закінчення -ом/-ем (ч.р. і с.р.), -ою/-ею (ж.р.), -ами/-ями (множина): ножем, водою, друзями. Він означає знаряддя (пишу ручкою), спосіб, а також іде після прийменників з, над, під, перед, за. Місцевий відмінок відповідає на «на кому? на чому?» і вживається ЛИШЕ з прийменниками в/у, на, при, по: у місті, на роботі, по обіді. Закінчення -і/-ї, -у (в місті, у лісі, на морі).","ru":"Творительный отвечает на «ким? чим?» с окончаниями -ом/-ем, -ою/-ею, -ами/-ями (ножем, водою, друзями): орудие, способ, а также после з, над, під, перед, за. Внимание: украинское -ою/-ею у ж.р. вместо русского -ой/-ей (водою, а не «водой»). Местный (предложный) употребляется ТОЛЬКО с в/у, на, при, по: у місті, на роботі. Часто -і там, где русский -е (в місті ← в городе).","en":"The instrumental answers 'with whom/what?' and ends in -ом/-ем, -ою/-ею, -ами/-ями (ножем, водою, друзями): it marks the tool (пишу ручкою), the means, and follows з, над, під, перед, за. The locative answers 'on/at what?' and appears ONLY with the prepositions в/у, на, при, по: у місті, на роботі, при вході. Its endings are -і/-ї and -у (в лісі, на морі).","de":"Der Instrumental antwortet auf 'mit wem/was?' und endet auf -ом/-ем, -ою/-ею, -ами/-ями (ножем, водою, друзями): er bezeichnet das Werkzeug (пишу ручкою), die Art und Weise und folgt auf з, над, під, перед, за. Der Lokativ antwortet auf 'wo?' und steht NUR mit den Präpositionen в/у, на, при, по: у місті, на роботі. Seine Endungen sind -і/-ї und -у (в лісі, на морі).","it":"Lo strumentale risponde a 'con chi/che cosa?' e termina in -ом/-ем, -ою/-ею, -ами/-ями (ножем, водою, друзями): indica lo strumento (пишу ручкою), il mezzo e segue з, над, під, перед, за. Il locativo risponde a 'dove?' e compare SOLO con le preposizioni в/у, на, при, по: у місті, на роботі. Le sue desinenze sono -і/-ї e -у (в лісі, на морі).","es_ar":"حالة الأداة تجيب عن «بمن؟ بماذا؟» وتنتهي بـ -ом/-ем و-ою/-ею و-ами/-ями (ножем، водою، друзями): تدلّ على الأداة (пишу ручкою) والوسيلة وتأتي بعد з، над، під، перед، за. أمّا الحالة الظرفية فتجيب عن «أين؟» ولا تأتي إلّا مع حروف الجرّ в/у، на، при، по: у місті، на роботі. ونهاياتها -і/-ї و-у (в лісі، на морі).","fr":"L'instrumental répond à « avec qui/quoi ? » et se termine en -ом/-ем, -ою/-ею, -ами/-ями (ножем, водою, друзями) : il marque l'outil (пишу ручкою), le moyen et suit з, над, під, перед, за. Le locatif répond à « où ? » et n'apparaît QU'avec les prépositions в/у, на, при, по : у місті, на роботі. Ses désinences sont -і/-ї et -у (в лісі, на морі)."},"tables":[{"caption":{"uk":"Орудний та місцевий: закінчення за родом","ru":"Творительный и местный: окончания по роду","en":"Instrumental & locative: endings by gender","de":"Instrumental & Lokativ: Endungen nach Genus","it":"Strumentale e locativo: desinenze per genere","es_ar":"حالتا الأداة والظرفية: النهايات حسب الجنس","fr":"Instrumental et locatif : désinences par genre"},"labelHeader":{"uk":"Рід / число","ru":"Род / число","en":"Gender / number","de":"Genus / Zahl","it":"Genere / numero","es_ar":"الجنس / العدد","fr":"Genre / nombre"},"columns":[{"uk":"Називний","ru":"Именительный","en":"Nominative","de":"Nominativ","it":"Nominativo","es_ar":"الرفع","fr":"Nominatif"},{"uk":"Орудний (ким? чим?)","ru":"Творительный","en":"Instrumental","de":"Instrumental","it":"Strumentale","es_ar":"الأداة","fr":"Instrumental"},{"uk":"Місцевий (на чому?)","ru":"Местный","en":"Locative","de":"Lokativ","it":"Locativo","es_ar":"الظرفية","fr":"Locatif"}],"rows":[{"label":{"uk":"чоловічий","ru":"мужской","en":"masculine","de":"maskulin","it":"maschile","es_ar":"مذكّر","fr":"masculin"},"cells":["стіл, ніж","столом, ножем","(на) столі, ножі"]},{"label":{"uk":"жіночий -а","ru":"женский -а","en":"feminine -а","de":"feminin -а","it":"femminile -а","es_ar":"مؤنّث -а","fr":"féminin -а"},"cells":["вода, земля","водою, землею","(у) воді, землі"]},{"label":{"uk":"середній","ru":"средний","en":"neuter","de":"neutrum","it":"neutro","es_ar":"محايد","fr":"neutre"},"cells":["місто, море","містом, морем","(у) місті, морі"]},{"label":{"uk":"жіночий на -ь","ru":"женский на -ь","en":"fem. in -ь","de":"feminin auf -ь","it":"femm. in -ь","es_ar":"مؤنّث على -ь","fr":"fém. en -ь"},"cells":["ніч, сіль","ніччю, сіллю","(у) ночі, солі"]},{"label":{"uk":"множина","ru":"множественное","en":"plural","de":"Plural","it":"plurale","es_ar":"الجمع","fr":"pluriel"},"cells":["друзі, книги","друзями, книгами","(на) друзях, книгах"]}]}],"examples":[{"uk":"Я пишу листа ручкою і розмовляю з другом.","ru":"Я пишу письмо ручкой и разговариваю с другом.","en":"I am writing a letter with a pen and talking with a friend.","de":"Ich schreibe einen Brief mit dem Kugelschreiber und spreche mit einem Freund.","it":"Scrivo una lettera con la penna e parlo con un amico.","es_ar":"أكتب رسالةً بالقلم وأتحدّث مع صديق.","fr":"J'écris une lettre avec un stylo et je parle avec un ami."},{"uk":"Ми живемо в місті, а працюємо на заводі.","ru":"Мы живём в городе, а работаем на заводе.","en":"We live in the city and work at the factory.","de":"Wir wohnen in der Stadt und arbeiten in der Fabrik.","it":"Viviamo in città e lavoriamo in fabbrica.","es_ar":"نعيش في المدينة ونعمل في المصنع.","fr":"Nous habitons en ville et travaillons à l'usine."},{"uk":"Над містом і під мостом літають птахи.","ru":"Над городом и под мостом летают птицы.","en":"Birds fly above the city and under the bridge.","de":"Über der Stadt und unter der Brücke fliegen Vögel.","it":"Sopra la città e sotto il ponte volano uccelli.","es_ar":"تطير الطيور فوق المدينة وتحت الجسر.","fr":"Des oiseaux volent au-dessus de la ville et sous le pont."}],"hints":{"ru":"Женский род в творительном оканчивается на -ою/-ею (водою, землею), а не на русское -ой/-ей. Местный падеж НЕ бывает без предлога: только в/у, на, при, по. Часто -і там, где русский -е: в місті, на столі, у лісі. После г/к/х идёт чередування: рука → у руці, нога → на нозі.","en":"The feminine instrumental ends in -ою/-ею (водою), not just -ой. The locative NEVER stands without a preposition — only в/у, на, при, по trigger it. Stems in г/к/х shift before -і: рука → у руці, нога → на нозі, книга → у книзі.","de":"Der feminine Instrumental endet auf -ою/-ею (водою). Der Lokativ steht NIE ohne Präposition — nur в/у, на, при, по lösen ihn aus. Stämme auf г/к/х wechseln vor -і: рука → у руці, нога → на нозі, книга → у книзі.","it":"Lo strumentale femminile finisce in -ою/-ею (водою). Il locativo NON esiste senza preposizione — solo в/у, на, при, по lo reggono. I temi in г/к/х si alternano davanti a -і: рука → у руці, нога → на нозі, книга → у книзі.","es_ar":"المؤنّث في حالة الأداة ينتهي بـ -ою/-ею (водою). أمّا الحالة الظرفية فلا تأتي أبدًا بلا حرف جرّ — يستدعيها فقط в/у، на، при، по. والجذور المنتهية بـ г/к/х تتبادل قبل -і: рука → у руці، нога → на нозі.","fr":"L'instrumental féminin se termine en -ою/-ею (водою). Le locatif n'existe JAMAIS sans préposition — seuls в/у, на, при, по le déclenchent. Les radicaux en г/к/х s'alternent devant -і : рука → у руці, нога → на нозі, книга → у книзі."}},
{"id":"verbs-of-motion","icon":"🚶","level":"B1","title":{"uk":"Дієслова руху та префікси","ru":"Глаголы движения и приставки","en":"Verbs of motion & prefixes","de":"Bewegungsverben & Präfixe","it":"Verbi di moto e prefissi","es_ar":"أفعال الحركة والبادئات","fr":"Verbes de mouvement et préfixes"},"intro":{"uk":"Дієслова руху йдуть парами: односпрямоване (в один бік, зараз) і різноспрямоване (туди-сюди, взагалі, регулярно). Пішки: іти (зараз іду) — ходити (регулярно ходжу). Транспортом: їхати (їду) — їздити (їжджу). Так само летіти — літати, нести — носити, бігти — бігати. Префікси змінюють напрямок: при- (наближення), ви- (назовні), в-/у- (всередину), пере- (через), від- (від), до- (до мети), з-/зі- (з місця).","ru":"Глаголы движения парные: однонаправленный (сейчас, в одну сторону) и разнонаправленный (туда-сюда, вообще). Пешком: іти (иду сейчас) — ходити (хожу регулярно). Транспортом: їхати — їздити. Внимание: пешком vs транспортом различаются жёстко, «идти» на машине нельзя. Приставки задают направление: при-, ви-, у-, пере-, від-, до-.","en":"Verbs of motion come in pairs: unidirectional (right now, one way) and multidirectional (back and forth, habitually). On foot: іти (I'm going now) — ходити (I go regularly). By vehicle: їхати — їздити. Ukrainian, unlike English, strictly separates going on foot from going by vehicle. Prefixes set direction: при- (arriving), ви- (out), в-/у- (in), пере- (across), від- (away), до- (up to).","de":"Bewegungsverben treten paarweise auf: gerichtet (jetzt, eine Richtung) und ungerichtet (hin und her, gewohnheitsmäßig). Zu Fuß: іти (ich gehe gerade) — ходити (ich gehe regelmäßig). Mit Fahrzeug: їхати — їздити. Anders als im Deutschen trennt das Ukrainische strikt Gehen zu Fuß vom Fahren. Präfixe geben die Richtung: при- (ankommen), ви- (hinaus), в-/у- (hinein), пере- (hinüber), від- (weg), до- (bis hin).","it":"I verbi di moto vanno a coppie: unidirezionale (ora, in una direzione) e pluridirezionale (avanti e indietro, abitualmente). A piedi: іти (sto andando ora) — ходити (vado di solito). In veicolo: їхати — їздити. A differenza dell'italiano, l'ucraino distingue nettamente l'andare a piedi dall'andare in mezzo. I prefissi danno la direzione: при- (arrivare), ви- (fuori), в-/у- (dentro), пере- (attraverso), від- (via), до- (fino a).","es_ar":"أفعال الحركة تأتي أزواجًا: أحادية الاتجاه (الآن، اتجاه واحد) ومتعددة الاتجاه (ذهابًا وإيابًا، بانتظام). سيرًا: іти (أذهب الآن) — ходити (أذهب بانتظام). بمركبة: їхати — їздити. وخلافًا للعربية، تفصل الأوكرانية بحزم بين المشي والركوب. والبادئات تحدّد الاتجاه: при- (الوصول)، ви- (الخروج)، в-/у- (الدخول)، пере- (العبور)، від- (الابتعاد)، до- (حتى).","fr":"Les verbes de mouvement vont par paires : unidirectionnel (maintenant, un sens) et multidirectionnel (aller-retour, habituellement). À pied : іти (je vais maintenant) — ходити (j'y vais régulièrement). En véhicule : їхати — їздити. Contrairement au français, l'ukrainien sépare strictement aller à pied et aller en véhicule. Les préfixes donnent la direction : при- (arriver), ви- (dehors), в-/у- (dedans), пере- (à travers), від- (loin), до- (jusqu'à)."},"tables":[{"caption":{"uk":"Пари дієслів руху та приклади з префіксами","ru":"Пары глаголов движения и примеры с приставками","en":"Pairs of motion verbs and prefixed examples","de":"Paare von Bewegungsverben und Beispiele mit Präfix","it":"Coppie di verbi di moto ed esempi con prefisso","es_ar":"أزواج أفعال الحركة وأمثلة بالبادئات","fr":"Paires de verbes de mouvement et exemples avec préfixe"},"labelHeader":{"uk":"Значення","ru":"Значение","en":"Meaning","de":"Bedeutung","it":"Significato","es_ar":"المعنى","fr":"Sens"},"columns":[{"uk":"Односпрямоване","ru":"Однонаправленный","en":"Unidirectional","de":"Gerichtet","it":"Unidirezionale","es_ar":"أحادي الاتجاه","fr":"Unidirectionnel"},{"uk":"Різноспрямоване","ru":"Разнонаправленный","en":"Multidirectional","de":"Ungerichtet","it":"Pluridirezionale","es_ar":"متعدد الاتجاه","fr":"Multidirectionnel"},{"uk":"З префіксом","ru":"С приставкой","en":"With prefix","de":"Mit Präfix","it":"Con prefisso","es_ar":"مع بادئة","fr":"Avec préfixe"}],"rows":[{"label":{"uk":"іти пішки","ru":"идти пешком","en":"go on foot","de":"zu Fuß gehen","it":"andare a piedi","es_ar":"الذهاب سيرًا","fr":"aller à pied"},"cells":["іти (іду, ідеш)","ходити (ходжу, ходиш)","прийти, вийти, зайти, перейти"]},{"label":{"uk":"їхати транспортом","ru":"ехать транспортом","en":"go by vehicle","de":"fahren","it":"andare in veicolo","es_ar":"الذهاب بمركبة","fr":"aller en véhicule"},"cells":["їхати (їду, їдеш)","їздити (їжджу, їздиш)","приїхати, виїхати, доїхати"]},{"label":{"uk":"летіти","ru":"лететь","en":"fly","de":"fliegen","it":"volare","es_ar":"الطيران","fr":"voler"},"cells":["летіти (лечу, летиш)","літати (літаю, літаєш)","прилетіти, відлетіти"]},{"label":{"uk":"нести","ru":"нести","en":"carry","de":"tragen","it":"portare","es_ar":"الحمل","fr":"porter"},"cells":["нести (несу, несеш)","носити (ношу, носиш)","принести, віднести, занести"]},{"label":{"uk":"бігти","ru":"бежать","en":"run","de":"laufen","it":"correre","es_ar":"الجري","fr":"courir"},"cells":["бігти (біжу, біжиш)","бігати (бігаю, бігаєш)","прибігти, вибігти, добігти"]}]}],"examples":[{"uk":"Зараз я йду до школи, а щодня ходжу пішки.","ru":"Сейчас я иду в школу, а каждый день хожу пешком.","en":"Right now I'm going to school, and every day I walk there.","de":"Gerade gehe ich zur Schule, und jeden Tag gehe ich zu Fuß.","it":"Adesso sto andando a scuola e ogni giorno ci vado a piedi.","es_ar":"الآن أنا ذاهبٌ إلى المدرسة، وكلّ يوم أذهب سيرًا.","fr":"En ce moment je vais à l'école, et chaque jour j'y vais à pied."},{"uk":"Влітку ми їздимо до бабусі, а завтра їдемо в Карпати.","ru":"Летом мы ездим к бабушке, а завтра едем в Карпаты.","en":"In summer we travel to grandma's, and tomorrow we're going to the Carpathians.","de":"Im Sommer fahren wir zur Oma, und morgen fahren wir in die Karpaten.","it":"D'estate andiamo dalla nonna, e domani andiamo nei Carpazi.","es_ar":"في الصيف نذهب إلى الجدّة، وغدًا نسافر إلى الكاربات.","fr":"En été nous allons chez grand-mère, et demain nous partons dans les Carpates."},{"uk":"Він прийшов додому, зайшов у кухню і вийшов на балкон.","ru":"Он пришёл домой, зашёл на кухню и вышел на балкон.","en":"He came home, went into the kitchen and stepped out onto the balcony.","de":"Er kam nach Hause, ging in die Küche und trat auf den Balkon hinaus.","it":"È tornato a casa, è entrato in cucina ed è uscito sul balcone.","es_ar":"عاد إلى البيت، ودخل المطبخ، وخرج إلى الشرفة.","fr":"Il est rentré à la maison, est entré dans la cuisine et est sorti sur le balcon."}],"hints":{"ru":"Пешком — только іти/ходити; транспортом — тільки їхати/їздити (нельзя «идти» на машине). Односпрямоване = сейчас, в одну сторону (іду); різноспрямоване = вообще, туда-сюда (ходжу). Приставка + односпрямований глагол даёт совершенный вид: прийти, приїхати. Обратите внимание на чергування: ходити → ходжу, їздити → їжджу.","en":"Use іти/ходити only for going on foot and їхати/їздити only for going by vehicle — never mix them. Unidirectional = now, one way (іду); multidirectional = in general, to and fro (ходжу). A prefix on the unidirectional verb makes it perfective: прийти, приїхати. Note stem shifts: ходити → ходжу, їздити → їжджу.","de":"іти/ходити nur zu Fuß, їхати/їздити nur mit Fahrzeug — nie vermischen. Gerichtet = jetzt, eine Richtung (іду); ungerichtet = allgemein, hin und her (ходжу). Ein Präfix am gerichteten Verb macht es perfektiv: прийти, приїхати. Beachten Sie den Wechsel: ходити → ходжу, їздити → їжджу.","it":"Usa іти/ходити solo a piedi e їхати/їздити solo in veicolo — mai mescolarli. Unidirezionale = ora, un senso (іду); pluridirezionale = in generale, avanti e indietro (ходжу). Un prefisso sul verbo unidirezionale lo rende perfettivo: прийти, приїхати. Attento all'alternanza: ходити → ходжу, їздити → їжджу.","es_ar":"استعمل іти/ходити للمشي فقط، وїхати/їздити للركوب فقط — لا تخلط بينهما. أحادي الاتجاه = الآن، اتجاه واحد (іду)؛ متعدد الاتجاه = عمومًا، ذهابًا وإيابًا (ходжу). إضافة بادئة إلى الفعل الأحادي تجعله تامًّا: прийти، приїхати. انتبه للتبادل: ходити → ходжу، їздити → їжджу.","fr":"Employez іти/ходити seulement à pied et їхати/їздити seulement en véhicule — jamais l'un pour l'autre. Unidirectionnel = maintenant, un sens (іду) ; multidirectionnel = en général, aller-retour (ходжу). Un préfixe sur le verbe unidirectionnel le rend perfectif : прийти, приїхати. Notez l'alternance : ходити → ходжу, їздити → їжджу."}},
{"id":"comparatives-superlatives","icon":"📊","level":"B1","title":{"uk":"Ступені порівняння прикметників","ru":"Степени сравнения прилагательных","en":"Comparatives & superlatives","de":"Steigerung der Adjektive","it":"Comparativi e superlativi","es_ar":"درجات المقارنة والتفضيل","fr":"Comparatif et superlatif"},"intro":{"uk":"Вищий ступінь утворюємо суфіксом -ший/-іший: новий → новіший, добрий → добріший. Часто чергування: дорогий → дорожчий, високий → вищий, дешевий → дешевший. Найвищий ступінь = префікс най- + вищий ступінь: найновіший, найдорожчий, найвищий. Для підсилення: якнай-, щонай- (якнайкращий). Порівняння вводять словом «ніж» або родовим відмінком без прийменника: більший, ніж брат = більший за брата.","ru":"Сравнительная степень — суффикс -ший/-іший: новий → новіший. Часто чередование: дорогий → дорожчий, високий → вищий. Превосходная = най- + сравнительная: найновіший, найвищий. Внимание: «чем» — это «ніж» (не «чем»): більший, ніж брат, или больший за брата (за + винительный). Есть и супплетивные: добрий → кращий, поганий → гірший.","en":"The comparative uses the suffix -ший/-іший: новий → новіший 'newer'. Consonant shifts are common: дорогий → дорожчий, високий → вищий, дешевий → дешевший. The superlative = prefix най- + comparative: найновіший, найвищий 'the newest/tallest'. Comparison is introduced by «ніж» or by «за» + accusative: більший, ніж брат = більший за брата 'bigger than a brother'.","de":"Der Komparativ bildet sich mit dem Suffix -ший/-іший: новий → новіший 'neuer'. Konsonantenwechsel sind häufig: дорогий → дорожчий, високий → вищий, дешевий → дешевший. Der Superlativ = Präfix най- + Komparativ: найновіший, найвищий 'am neuesten/höchsten'. Der Vergleich wird mit «ніж» oder «за» + Akkusativ eingeleitet: більший, ніж брат = більший за брата 'größer als ein Bruder'.","it":"Il comparativo usa il suffisso -ший/-іший: новий → новіший 'più nuovo'. Sono frequenti le alternanze: дорогий → дорожчий, високий → вищий, дешевий → дешевший. Il superlativo = prefisso най- + comparativo: найновіший, найвищий 'il più nuovo/alto'. Il paragone si introduce con «ніж» o con «за» + accusativo: більший, ніж брат = більший за брата 'più grande di un fratello'.","es_ar":"درجة المقارنة تُبنى باللاحقة -ший/-іший: новий → новіший «أحدث». والتبادلات شائعة: дорогий → дорожчий، високий → вищий، дешевий → дешевший. ودرجة التفضيل = البادئة най- + درجة المقارنة: найновіший، найвищий «الأحدث/الأعلى». وتُدخَل المقارنة بـ«ніж» أو بـ«за» + النصب: більший, ніж брат = більший за брата «أكبر من أخ».","fr":"Le comparatif emploie le suffixe -ший/-іший : новий → новіший « plus neuf ». Les alternances sont fréquentes : дорогий → дорожчий, високий → вищий, дешевий → дешевший. Le superlatif = préfixe най- + comparatif : найновіший, найвищий « le plus neuf/haut ». La comparaison s'introduit par «ніж» ou par «за» + accusatif : більший, ніж брат = більший за брата « plus grand qu'un frère »."},"tables":[{"caption":{"uk":"Звичайний → вищий → найвищий","ru":"Обычный → сравнительный → превосходный","en":"Positive → comparative → superlative","de":"Positiv → Komparativ → Superlativ","it":"Positivo → comparativo → superlativo","es_ar":"العادي ← المقارنة ← التفضيل","fr":"Positif → comparatif → superlatif"},"labelHeader":{"uk":"Прикметник","ru":"Прилагательное","en":"Adjective","de":"Adjektiv","it":"Aggettivo","es_ar":"الصفة","fr":"Adjectif"},"columns":[{"uk":"Звичайний","ru":"Обычный","en":"Positive","de":"Positiv","it":"Positivo","es_ar":"العادي","fr":"Positif"},{"uk":"Вищий","ru":"Сравнительный","en":"Comparative","de":"Komparativ","it":"Comparativo","es_ar":"المقارنة","fr":"Comparatif"},{"uk":"Найвищий","ru":"Превосходный","en":"Superlative","de":"Superlativ","it":"Superlativo","es_ar":"التفضيل","fr":"Superlatif"}],"rows":[{"label":{"uk":"новий","ru":"новый","en":"new","de":"neu","it":"nuovo","es_ar":"جديد","fr":"neuf"},"cells":["новий","новіший","найновіший"]},{"label":{"uk":"дорогий","ru":"дорогой","en":"expensive","de":"teuer","it":"caro","es_ar":"غالٍ","fr":"cher"},"cells":["дорогий","дорожчий","найдорожчий"]},{"label":{"uk":"високий","ru":"высокий","en":"tall/high","de":"hoch","it":"alto","es_ar":"عالٍ","fr":"haut"},"cells":["високий","вищий","найвищий"]},{"label":{"uk":"добрий (суплетив)","ru":"хороший (супплетив)","en":"good (suppletive)","de":"gut (suppletiv)","it":"buono (suppletivo)","es_ar":"جيّد (شاذّ)","fr":"bon (supplétif)"},"cells":["добрий / гарний","кращий / ліпший","найкращий / найліпший"]},{"label":{"uk":"поганий (суплетив)","ru":"плохой (супплетив)","en":"bad (suppletive)","de":"schlecht (suppletiv)","it":"cattivo (suppletivo)","es_ar":"سيّئ (شاذّ)","fr":"mauvais (supplétif)"},"cells":["поганий","гірший","найгірший"]}]}],"examples":[{"uk":"Київ більший, ніж Львів. / Київ більший за Львів.","ru":"Киев больше, чем Львов. / Киев больше Львова.","en":"Kyiv is bigger than Lviv.","de":"Kyjiw ist größer als Lwiw.","it":"Kyiv è più grande di Leopoli.","es_ar":"كييف أكبر من لفيف.","fr":"Kyiv est plus grande que Lviv."},{"uk":"Це найцікавіша книга, яку я читав.","ru":"Это самая интересная книга, которую я читал.","en":"This is the most interesting book I have read.","de":"Das ist das interessanteste Buch, das ich gelesen habe.","it":"Questo è il libro più interessante che abbia letto.","es_ar":"هذا أكثر كتاب مثير للاهتمام قرأته.","fr":"C'est le livre le plus intéressant que j'aie lu."},{"uk":"Сьогодні погода краща, ніж учора, але завтра буде найтепліший день.","ru":"Сегодня погода лучше, чем вчера, но завтра будет самый тёплый день.","en":"Today the weather is better than yesterday, but tomorrow will be the warmest day.","de":"Heute ist das Wetter besser als gestern, aber morgen wird der wärmste Tag.","it":"Oggi il tempo è migliore di ieri, ma domani sarà il giorno più caldo.","es_ar":"الطقس اليوم أفضل من أمس، لكنّ الغد سيكون أدفأ يوم.","fr":"Aujourd'hui le temps est meilleur qu'hier, mais demain sera le jour le plus chaud."}],"hints":{"ru":"«Чем» переводится как «ніж», не «чем»: більший, ніж… Второй способ — «за» + винительный (більший за брата) или родительный без предлога (більший брата). Помните чередования: дорогий → дорожчий, дужий → дужчий, високий → вищий. И супплетивы: добрий → кращий, поганий → гірший.","en":"Say «ніж» for 'than', or use «за» + accusative (більший за брата), or a bare genitive (більший брата). Watch for stem shifts before -ший: дорогий → дорожчий, високий → вищий. Learn the suppletive pairs by heart: добрий → кращий, поганий → гірший.","de":"'als' heißt «ніж», oder man nimmt «за» + Akkusativ (більший за брата) bzw. den bloßen Genitiv (більший брата). Beachten Sie den Wechsel vor -ший: дорогий → дорожчий, високий → вищий. Lernen Sie die suppletiven Paare: добрий → кращий, поганий → гірший.","it":"'di/che' si rende con «ніж», oppure con «за» + accusativo (більший за брата) o col genitivo semplice (більший брата). Attento all'alternanza davanti a -ший: дорогий → дорожчий, високий → вищий. Impara le coppie suppletive: добрий → кращий, поганий → гірший.","es_ar":"«من» في المقارنة تُترجم بـ«ніж»، أو بـ«за» + النصب (більший за брата)، أو بالجرّ المجرّد (більший брата). انتبه للتبادل قبل -ший: дорогий → дорожчий، високий → вищий. واحفظ الأزواج الشاذّة: добрий → кращий، поганий → гірший.","fr":"« que » se dit «ніж», ou l'on emploie «за» + accusatif (більший за брата) ou le génitif seul (більший брата). Attention à l'alternance devant -ший : дорогий → дорожчий, високий → вищий. Apprenez les paires supplétives : добрий → кращий, поганий → гірший."}},
{"id":"conditional-shchob","icon":"💭","level":"B1","title":{"uk":"Умовний спосіб (би/б) та сполучник «щоб»","ru":"Условное наклонение (би/б) и союз «щоб»","en":"Conditional mood (би/б) & «щоб»","de":"Konditional (би/б) & die Konjunktion «щоб»","it":"Condizionale (би/б) e la congiunzione «щоб»","es_ar":"صيغة الشرط (би/б) وأداة الربط «щоб»","fr":"Le conditionnel (би/б) et la conjonction «щоб»"},"intro":{"uk":"Умовний спосіб утворюємо просто: форма минулого часу + частка би/б. «Б» ставимо після голосного (я хотів би, вона знала б), «би» — після приголосного (я зробив би). Частка рухлива: може стояти після сполучника (якби, щоб), після дієслова чи іншого слова. Сполучник «щоб» (= що + б) вводить мету або бажання й теж вимагає дієслова у формі на -в/-ла/-ло/-ли: «Хочу, щоб ти прийшов». «Якби» вводить нереальну умову: «Якби я мав час, я б відпочив».","ru":"Условное наклонение = форма прошедшего времени + частица би/б. «Б» после гласного (хотів би, знала б), «би» после согласного (зробив би). Частица подвижная, часто сливается с союзами: якби, щоб. Союз «щоб» (= чтобы) требует глагола в форме на -в/-ла/-ло/-ли, а не инфинитива, когда подлежащие разные: «Хочу, щоб ти прийшов». «Якби» = если бы (нереальное условие).","en":"The conditional is formed simply: the past-tense form + the particle би/б. Use «б» after a vowel (я хотів би, вона знала б) and «би» after a consonant (я зробив би). The particle is mobile and fuses with conjunctions: якби, щоб. The conjunction «щоб» (= 'so that / in order to') introduces purpose or a wish and also takes the -в/-ла/-ло/-ли form: «Хочу, щоб ти прийшов» ('I want you to come'). «Якби» introduces an unreal condition: «Якби я мав час…» ('If I had time…').","de":"Der Konditional wird einfach gebildet: die Vergangenheitsform + die Partikel би/б. «б» nach Vokal (я хотів би, вона знала б), «би» nach Konsonant (я зробив би). Die Partikel ist beweglich und verschmilzt mit Konjunktionen: якби, щоб. Die Konjunktion «щоб» ('damit / um zu') leitet Zweck oder Wunsch ein und verlangt ebenfalls die Form auf -в/-ла/-ло/-ли: «Хочу, щоб ти прийшов» ('Ich will, dass du kommst'). «Якби» leitet eine irreale Bedingung ein: «Якби я мав час…».","it":"Il condizionale si forma facilmente: la forma del passato + la particella би/б. Si usa «б» dopo vocale (я хотів би, вона знала б) e «би» dopo consonante (я зробив би). La particella è mobile e si fonde con le congiunzioni: якби, щоб. La congiunzione «щоб» ('affinché / per') introduce scopo o desiderio e vuole anch'essa la forma in -в/-ла/-ло/-ли: «Хочу, щоб ти прийшов» ('Voglio che tu venga'). «Якби» introduce una condizione irreale: «Якби я мав час…».","es_ar":"تُبنى صيغة الشرط ببساطة: صيغة الماضي + الأداة би/б. تُستعمل «б» بعد حرف علة (я хотів би، вона знала б) و«би» بعد ساكن (я зробив би). والأداة متحركة وتندمج مع أدوات الربط: якби، щоб. وأداة الربط «щоб» (أي «كي/لكي») تُدخل الغرض أو الرغبة وتتطلّب كذلك الصيغة على -в/-ла/-ло/-ли: «Хочу, щоб ти прийшов» (أريدك أن تأتي). أمّا «якби» فتُدخل شرطًا غير واقعي: «Якби я мав час…».","fr":"Le conditionnel se forme simplement : la forme du passé + la particule би/б. On emploie «б» après une voyelle (я хотів би, вона знала б) et «би» après une consonne (я зробив би). La particule est mobile et fusionne avec les conjonctions : якби, щоб. La conjonction «щоб» (« pour que / afin de ») introduit le but ou le souhait et exige aussi la forme en -в/-ла/-ло/-ли : «Хочу, щоб ти прийшов» (« je veux que tu viennes »). «Якби» introduit une condition irréelle : «Якби я мав час…»."},"tables":[{"caption":{"uk":"Умовний спосіб та конструкції зі «щоб / якби»","ru":"Условное наклонение и конструкции со «щоб / якби»","en":"Conditional and «щоб / якби» constructions","de":"Konditional und Konstruktionen mit «щоб / якби»","it":"Condizionale e costrutti con «щоб / якби»","es_ar":"صيغة الشرط والتراكيب مع «щоб / якби»","fr":"Conditionnel et constructions avec «щоб / якби»"},"labelHeader":{"uk":"Конструкція","ru":"Конструкция","en":"Construction","de":"Konstruktion","it":"Costrutto","es_ar":"التركيب","fr":"Construction"},"columns":[{"uk":"Форма","ru":"Форма","en":"Form","de":"Form","it":"Forma","es_ar":"الصيغة","fr":"Forme"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"би після приголосного","ru":"би после согласного","en":"би after consonant","de":"би nach Konsonant","it":"би dopo consonante","es_ar":"би بعد ساكن","fr":"би après consonne"},"cells":["минулий + би","Я зробив би це."]},{"label":{"uk":"б після голосного","ru":"б после гласного","en":"б after vowel","de":"б nach Vokal","it":"б dopo vocale","es_ar":"б بعد حرف علة","fr":"б après voyelle"},"cells":["минулий + б","Вона знала б відповідь."]},{"label":{"uk":"нереальна умова","ru":"нереальное условие","en":"unreal condition","de":"irreale Bedingung","it":"condizione irreale","es_ar":"شرط غير واقعي","fr":"condition irréelle"},"cells":["якби …, (то) … би","Якби я мав час, я б відпочив."]},{"label":{"uk":"мета / бажання","ru":"цель / желание","en":"purpose / wish","de":"Zweck / Wunsch","it":"scopo / desiderio","es_ar":"غرض / رغبة","fr":"but / souhait"},"cells":["щоб + -в/-ла/-ло/-ли","Хочу, щоб ти прийшов."]},{"label":{"uk":"мета (та сама особа)","ru":"цель (то же лицо)","en":"purpose (same subject)","de":"Zweck (gleiches Subjekt)","it":"scopo (stesso soggetto)","es_ar":"غرض (الفاعل نفسه)","fr":"but (même sujet)"},"cells":["щоб + інфінітив","Я вчуся, щоб знати мову."]}]}],"examples":[{"uk":"Якби я був багатим, я б подорожував світом.","ru":"Если бы я был богатым, я бы путешествовал по миру.","en":"If I were rich, I would travel the world.","de":"Wenn ich reich wäre, würde ich um die Welt reisen.","it":"Se fossi ricco, viaggerei per il mondo.","es_ar":"لو كنت غنيًّا، لسافرت حول العالم.","fr":"Si j'étais riche, je voyagerais à travers le monde."},{"uk":"Мама хоче, щоб ми більше читали.","ru":"Мама хочет, чтобы мы больше читали.","en":"Mum wants us to read more.","de":"Mama will, dass wir mehr lesen.","it":"La mamma vuole che leggiamo di più.","es_ar":"تريد أمّي أن نقرأ أكثر.","fr":"Maman veut que nous lisions davantage."},{"uk":"Я прийшов раніше, щоб зайняти хороше місце.","ru":"Я пришёл раньше, чтобы занять хорошее место.","en":"I came earlier in order to take a good seat.","de":"Ich kam früher, um einen guten Platz zu bekommen.","it":"Sono arrivato prima per prendere un buon posto.","es_ar":"أتيت مبكّرًا كي آخذ مكانًا جيّدًا.","fr":"Je suis venu plus tôt pour prendre une bonne place."}],"hints":{"ru":"Нет отдельной формы условного — только прошедшее + би/б. Выбор: «б» после гласного (я б, вона знала б), «би» после согласного (зробив би). После «щоб» и «якби» глагол в форме на -в/-ла/-ло/-ли, НЕ будущее и НЕ настоящее: «Хочу, щоб ти прийшов» (не «прийдеш»). Если подлежащее одно и то же, после «щоб» можно инфинитив.","en":"There is no separate conditional form — just past tense + би/б. Choose «б» after a vowel (я б, вона знала б) and «би» after a consonant (зробив би). After «щоб» and «якби», the verb takes the -в/-ла/-ло/-ли form, never the future or present: «Хочу, щоб ти прийшов» (not «прийдеш»). With one and the same subject, «щоб» can take an infinitive.","de":"Es gibt keine eigene Konditionalform — nur Vergangenheit + би/б. Wählen Sie «б» nach Vokal (я б, вона знала б), «би» nach Konsonant (зробив би). Nach «щоб» und «якби» steht die Form auf -в/-ла/-ло/-ли, nie Futur oder Präsens: «Хочу, щоб ти прийшов» (nicht «прийдеш»). Bei gleichem Subjekt kann nach «щоб» ein Infinitiv stehen.","it":"Non esiste una forma condizionale a sé — solo passato + би/б. Scegli «б» dopo vocale (я б, вона знала б), «би» dopo consonante (зробив би). Dopo «щоб» e «якби» il verbo prende la forma in -в/-ла/-ло/-ли, mai il futuro o il presente: «Хочу, щоб ти прийшов» (non «прийдеш»). Con lo stesso soggetto, «щоб» può reggere l'infinito.","es_ar":"لا توجد صيغة شرط مستقلّة — فقط الماضي + би/б. اختر «б» بعد حرف علة (я б، вона знала б)، و«би» بعد ساكن (зробив би). بعد «щоб» و«якби» يأتي الفعل بصيغة -в/-ла/-ло/-ли، لا المستقبل ولا المضارع: «Хочу, щоб ти прийшов» (لا «прийдеш»). وإذا كان الفاعل نفسه، جاز بعد «щоб» المصدر.","fr":"Il n'y a pas de forme conditionnelle propre — seulement le passé + би/б. Choisissez «б» après une voyelle (я б, вона знала б), «би» après une consonne (зробив би). Après «щоб» et «якби», le verbe prend la forme en -в/-ла/-ло/-ли, jamais le futur ni le présent : «Хочу, щоб ти прийшов» (pas «прийдеш»). Avec le même sujet, «щоб» peut régir un infinitif."}},
{"id":"word-order-conjunctions","icon":"🔗","level":"B1","title":{"uk":"Порядок слів та сполучники","ru":"Порядок слов и союзы","en":"Word order & conjunctions","de":"Wortstellung & Konjunktionen","it":"Ordine delle parole e congiunzioni","es_ar":"ترتيب الكلمات وأدوات الربط","fr":"Ordre des mots et conjonctions"},"intro":{"uk":"Звичайний порядок слів — «підмет–присудок–додаток» (Я читаю книгу), але завдяки відмінкам він вільний: можна сказати «Книгу я читаю», щоб наголосити на книзі. Найважливіша (нова) інформація зазвичай стоїть у кінці речення. Сполучники сурядні поєднують рівноправні частини: і/й, та, а, але, або, чи. Підрядні вводять залежні речення: що, щоб, бо, тому що, коли, якщо, хоча, який. Перед підрядним сполучником звичайно ставимо кому.","ru":"Обычный порядок — «подлежащее–сказуемое–дополнение», но благодаря падежам он свободный: «Книгу я читаю» подчёркивает книгу. Новое/важное обычно в конце. Сочинительные союзы: і/й, та, а, але, або, чи. Подчинительные: що, щоб, бо, тому що, коли, якщо, хоча, який. Внимание: «і» перед гласным часто становится «й» (він і вона, але ти й вона). Перед подчинительным союзом ставится запятая.","en":"The default order is subject–verb–object (Я читаю книгу), but because cases mark roles, order is free: «Книгу я читаю» foregrounds the book. New or important information usually comes last. Coordinating conjunctions join equals: і/й, та ('and'), а ('but/and'), але ('but'), або, чи ('or'). Subordinating conjunctions introduce clauses: що, щоб, бо, тому що, коли, якщо, хоча, який. A comma normally precedes a subordinating conjunction.","de":"Die Grundstellung ist Subjekt–Verb–Objekt (Я читаю книгу), doch dank der Kasus ist sie frei: «Книгу я читаю» hebt das Buch hervor. Neue oder wichtige Information steht meist am Ende. Nebenordnende Konjunktionen verbinden Gleichrangiges: і/й, та ('und'), а ('aber/und'), але ('aber'), або, чи ('oder'). Unterordnende leiten Nebensätze ein: що, щоб, бо, тому що, коли, якщо, хоча, який. Vor einer unterordnenden Konjunktion steht meist ein Komma.","it":"L'ordine base è soggetto–verbo–oggetto (Я читаю книгу), ma grazie ai casi è libero: «Книгу я читаю» mette in rilievo il libro. L'informazione nuova o importante di solito va in fondo. Le congiunzioni coordinanti uniscono elementi pari: і/й, та ('e'), а ('ma/e'), але ('ma'), або, чи ('o'). Le subordinanti introducono le frasi dipendenti: що, щоб, бо, тому що, коли, якщо, хоча, який. Prima di una subordinante si mette di norma la virgola.","es_ar":"الترتيب الأساسي هو فاعل–فعل–مفعول (Я читаю книгу)، لكن بفضل الحالات فهو حرّ: «Книгу я читаю» يُبرز الكتاب. والمعلومة الجديدة أو المهمّة تأتي غالبًا في النهاية. أدوات العطف تربط بين متساويَين: і/й، та («و»)، а («لكن/و»)، але («لكن»)، або، чи («أو»). وأدوات الربط التبعية تُدخل الجمل التابعة: що، щоб، бо، тому що، коли، якщо، хоча، який. وتُوضَع فاصلة عادةً قبل الأداة التبعية.","fr":"L'ordre de base est sujet–verbe–objet (Я читаю книгу), mais grâce aux cas il est libre : «Книгу я читаю» met le livre en avant. L'information nouvelle ou importante vient d'ordinaire à la fin. Les conjonctions de coordination joignent des éléments égaux : і/й, та (« et »), а (« mais/et »), але (« mais »), або, чи (« ou »). Les subordonnantes introduisent les propositions dépendantes : що, щоб, бо, тому що, коли, якщо, хоча, який. Une virgule précède normalement la conjonction de subordination."},"tables":[{"caption":{"uk":"Основні сполучники та їхнє значення","ru":"Основные союзы и их значение","en":"Main conjunctions and their meaning","de":"Wichtige Konjunktionen und ihre Bedeutung","it":"Congiunzioni principali e loro significato","es_ar":"أهمّ أدوات الربط ومعانيها","fr":"Principales conjonctions et leur sens"},"labelHeader":{"uk":"Значення","ru":"Значение","en":"Meaning","de":"Bedeutung","it":"Significato","es_ar":"المعنى","fr":"Sens"},"columns":[{"uk":"Сполучник","ru":"Союз","en":"Conjunction","de":"Konjunktion","it":"Congiunzione","es_ar":"الأداة","fr":"Conjonction"},{"uk":"Приклад","ru":"Пример","en":"Example","de":"Beispiel","it":"Esempio","es_ar":"مثال","fr":"Exemple"}],"rows":[{"label":{"uk":"поєднання (і)","ru":"соединение (и)","en":"addition (and)","de":"Verbindung (und)","it":"aggiunta (e)","es_ar":"الإضافة (و)","fr":"addition (et)"},"cells":["і / й, та","Я читаю і пишу."]},{"label":{"uk":"протиставлення (але)","ru":"противопоставление (но)","en":"contrast (but)","de":"Gegensatz (aber)","it":"contrasto (ma)","es_ar":"التقابل (لكن)","fr":"opposition (mais)"},"cells":["а, але, проте","Я хочу, але не можу."]},{"label":{"uk":"вибір (або)","ru":"выбор (или)","en":"choice (or)","de":"Wahl (oder)","it":"scelta (o)","es_ar":"الاختيار (أو)","fr":"choix (ou)"},"cells":["або, чи","Чай або кава?"]},{"label":{"uk":"причина (бо)","ru":"причина (потому что)","en":"cause (because)","de":"Grund (weil)","it":"causa (perché)","es_ar":"السبب (لأنّ)","fr":"cause (parce que)"},"cells":["бо, тому що","Я вдома, бо йде дощ."]},{"label":{"uk":"умова / час","ru":"условие / время","en":"condition / time","de":"Bedingung / Zeit","it":"condizione / tempo","es_ar":"شرط / زمن","fr":"condition / temps"},"cells":["якщо, коли","Якщо буде час, зателефоную."]},{"label":{"uk":"допуст (хоча)","ru":"уступка (хотя)","en":"concession (although)","de":"Einräumung (obwohl)","it":"concessione (benché)","es_ar":"التنازل (رغم أنّ)","fr":"concession (bien que)"},"cells":["хоча, незважаючи на те що","Хоча було пізно, ми гуляли."]}]}],"examples":[{"uk":"Я люблю каву, а моя сестра надає перевагу чаю.","ru":"Я люблю кофе, а моя сестра предпочитает чай.","en":"I like coffee, whereas my sister prefers tea.","de":"Ich mag Kaffee, meine Schwester dagegen bevorzugt Tee.","it":"A me piace il caffè, mentre mia sorella preferisce il tè.","es_ar":"أنا أحبّ القهوة، أمّا أختي فتفضّل الشاي.","fr":"J'aime le café, tandis que ma sœur préfère le thé."},{"uk":"Ми залишилися вдома, бо йшов сильний дощ.","ru":"Мы остались дома, потому что шёл сильный дождь.","en":"We stayed home because it was raining hard.","de":"Wir blieben zu Hause, weil es stark regnete.","it":"Siamo rimasti a casa perché pioveva forte.","es_ar":"بقينا في البيت لأنّ المطر كان غزيرًا.","fr":"Nous sommes restés à la maison parce qu'il pleuvait fort."},{"uk":"Цю книгу я вже прочитав, а ту ще ні.","ru":"Эту книгу я уже прочитал, а ту ещё нет.","en":"This book I have already read, but that one not yet.","de":"Dieses Buch habe ich schon gelesen, jenes noch nicht.","it":"Questo libro l'ho già letto, ma quello no ancora.","es_ar":"هذا الكتاب قرأته بالفعل، أمّا ذاك فلا بعد.","fr":"Ce livre-ci, je l'ai déjà lu, mais celui-là pas encore."}],"hints":{"ru":"Различайте «а» (мягкое противопоставление/сопоставление, ≈ «а») и «але» (сильное «но»). «І» перед согласным, «й» — для благозвучия после гласного (вона й він). «Бо» ставится только в середине, а «тому що» может начинать пояснение. Перед що, щоб, бо, коли, якщо, який ставьте запятую.","en":"Distinguish «а» (mild contrast/juxtaposition, 'whereas/and') from «але» (strong 'but'). Use «і» before a consonant and «й» for euphony after a vowel (вона й він). «Бо» only stands mid-sentence, while «тому що» can open the reason. Put a comma before що, щоб, бо, коли, якщо, який.","de":"Unterscheiden Sie «а» (leichter Gegensatz/Gegenüberstellung, 'wohingegen/und') von «але» (starkes 'aber'). «і» vor Konsonant, «й» aus Wohlklang nach Vokal (вона й він). «Бо» steht nur im Satzinneren, «тому що» kann den Grund einleiten. Vor що, щоб, бо, коли, якщо, який steht ein Komma.","it":"Distingui «а» (contrasto lieve/accostamento, 'mentre/e') da «але» ('ma' forte). Usa «і» davanti a consonante e «й» per eufonia dopo vocale (вона й він). «Бо» sta solo a metà frase, mentre «тому що» può aprire la causa. Metti la virgola prima di що, щоб, бо, коли, якщо, який.","es_ar":"ميّز بين «а» (تقابل خفيف/مقابلة، «بينما/و») و«але» («لكن» القوية). استعمل «і» قبل الساكن و«й» للتناغم بعد حرف علة (вона й він). و«бо» لا تأتي إلّا في وسط الجملة، بينما «тому що» يمكن أن تبدأ التعليل. وضَع فاصلة قبل що، щоб، бо، коли، якщо، який.","fr":"Distinguez «а» (opposition légère/juxtaposition, « tandis que/et ») de «але» (« mais » fort). Employez «і» devant une consonne et «й» par euphonie après une voyelle (вона й він). «Бо» ne se place qu'en milieu de phrase, alors que «тому що» peut ouvrir la cause. Mettez une virgule avant що, щоб, бо, коли, якщо, який."}},
{"id":"numerals-declension","icon":"🔟","level":"B1","title":{"uk":"Відмінювання числівників","ru":"Склонение числительных","en":"Declension of numerals","de":"Deklination der Zahlwörter","it":"Declinazione dei numerali","es_ar":"تصريف الأعداد","fr":"Déclinaison des numéraux"},"intro":{"uk":"Числівники в українській відмінюються, як і іменники. «Один» змінюється як прикметник (одного, одному, одним). «Два, три, чотири» мають власні форми (двох, трьох, чотирьох). «П'ять» і далі відмінюються як іменники на -ь (п'яти/п'ятьох, п'ятьома). У складених числівниках відмінюється КОЖНЕ слово: двадцять п'ять → двадцяти п'яти. У порядкових числівниках (перший, другий) відмінюється лише останнє слово: двадцять п'ятий → двадцять п'ятого. «Сорок, дев'яносто, сто» у непрямих відмінках мають форму на -а: сорока, дев'яноста, ста.","ru":"Числительные склоняются. «Один» — как прилагательное (одного, одному, одним). «Два, три, чотири» — особые формы (двох, трьох, чотирьох). «П'ять»+ склоняются как существительные на -ь (п'яти/п'ятьох, п'ятьма/п'ятьома). Важно: в составных количественных склоняется КАЖДОЕ слово (двадцяти п'яти), а в порядковых — только последнее (двадцять п'ятого). «Сорок, дев'яносто, сто» дают сорока, дев'яноста, ста.","en":"Ukrainian numerals decline like nouns. «Один» inflects like an adjective (одного, одному, одним). «Два, три, чотири» have their own forms (двох, трьох, чотирьох). From «п'ять» up they decline like soft-sign nouns (п'яти/п'ятьох, п'ятьома). In compound cardinals EVERY word declines: двадцять п'ять → двадцяти п'яти. In ordinals (перший, другий) only the LAST word declines: двадцять п'ятий → двадцять п'ятого. «Сорок, дев'яносто, сто» take -а in the oblique cases: сорока, дев'яноста, ста.","de":"Ukrainische Zahlwörter werden wie Substantive dekliniert. «Один» geht wie ein Adjektiv (одного, одному, одним). «Два, три, чотири» haben eigene Formen (двох, трьох, чотирьох). Ab «п'ять» dekliniert man wie Substantive auf -ь (п'яти/п'ятьох, п'ятьома). Bei zusammengesetzten Grundzahlen wird JEDES Wort dekliniert: двадцять п'ять → двадцяти п'яти. Bei Ordnungszahlen (перший, другий) nur das LETZTE Wort: двадцять п'ятий → двадцять п'ятого. «Сорок, дев'яносто, сто» haben -а: сорока, дев'яноста, ста.","it":"I numerali ucraini si declinano come i nomi. «Один» si flette come un aggettivo (одного, одному, одним). «Два, три, чотири» hanno forme proprie (двох, трьох, чотирьох). Da «п'ять» in su si declinano come i nomi in -ь (п'яти/п'ятьох, п'ятьома). Nei cardinali composti si declina OGNI parola: двадцять п'ять → двадцяти п'яти. Negli ordinali (перший, другий) solo l'ULTIMA parola: двадцять п'ятий → двадцять п'ятого. «Сорок, дев'яносто, сто» prendono -а: сорока, дев'яноста, ста.","es_ar":"تُصرَّف الأعداد الأوكرانية كالأسماء. «Один» يتصرّف كصفة (одного، одному، одним). و«два، три، чотири» لها صيغ خاصّة (двох، трьох، чотирьох). ومن «п'ять» فصاعدًا تُصرَّف كالأسماء المنتهية بـ -ь (п'яти/п'ятьох، п'ятьома). وفي الأعداد المركّبة تُصرَّف كلّ كلمة: двадцять п'ять → двадцяти п'яти. أمّا الترتيبية (перший، другий) فتُصرَّف كلمتها الأخيرة فقط: двадцять п'ятий → двадцять п'ятого. و«сорок، дев'яносто، сто» تأخذ -а: сорока، дев'яноста، ста.","fr":"Les numéraux ukrainiens se déclinent comme les noms. «Один» se fléchit comme un adjectif (одного, одному, одним). «Два, три, чотири» ont leurs propres formes (двох, трьох, чотирьох). À partir de «п'ять» ils se déclinent comme les noms en -ь (п'яти/п'ятьох, п'ятьома). Dans les cardinaux composés, CHAQUE mot se décline : двадцять п'ять → двадцяти п'яти. Dans les ordinaux (перший, другий), seul le DERNIER mot se décline : двадцять п'ятий → двадцять п'ятого. «Сорок, дев'яносто, сто» prennent -а : сорока, дев'яноста, ста."},"tables":[{"caption":{"uk":"Відмінювання числівників «один, два, п'ять»","ru":"Склонение числительных «один, два, п'ять»","en":"Declension of «один, два, п'ять»","de":"Deklination von «один, два, п'ять»","it":"Declinazione di «один, два, п'ять»","es_ar":"تصريف «один، два، п'ять»","fr":"Déclinaison de «один, два, п'ять»"},"labelHeader":{"uk":"Відмінок","ru":"Падеж","en":"Case","de":"Kasus","it":"Caso","es_ar":"الحالة","fr":"Cas"},"columns":[{"uk":"один (ч.р.)","ru":"один (м.р.)","en":"один (masc.)","de":"один (m.)","it":"один (m.)","es_ar":"один (مذكّر)","fr":"один (m.)"},{"uk":"два","ru":"два","en":"два","de":"два","it":"два","es_ar":"два","fr":"два"},{"uk":"п'ять","ru":"п'ять","en":"п'ять","de":"п'ять","it":"п'ять","es_ar":"п'ять","fr":"п'ять"}],"rows":[{"label":{"uk":"називний (Н.)","ru":"именительный","en":"nominative","de":"Nominativ","it":"nominativo","es_ar":"الرفع","fr":"nominatif"},"cells":["один","два","п'ять"]},{"label":{"uk":"родовий (Р.)","ru":"родительный","en":"genitive","de":"Genitiv","it":"genitivo","es_ar":"الجرّ","fr":"génitif"},"cells":["одного","двох","п'яти / п'ятьох"]},{"label":{"uk":"давальний (Д.)","ru":"дательный","en":"dative","de":"Dativ","it":"dativo","es_ar":"المفعول له","fr":"datif"},"cells":["одному","двом","п'яти / п'ятьом"]},{"label":{"uk":"знахідний (З.)","ru":"винительный","en":"accusative","de":"Akkusativ","it":"accusativo","es_ar":"النصب","fr":"accusatif"},"cells":["один / одного","два / двох","п'ять / п'ятьох"]},{"label":{"uk":"орудний (О.)","ru":"творительный","en":"instrumental","de":"Instrumental","it":"strumentale","es_ar":"الأداة","fr":"instrumental"},"cells":["одним","двома","п'ятьма / п'ятьома"]},{"label":{"uk":"місцевий (М.)","ru":"местный","en":"locative","de":"Lokativ","it":"locativo","es_ar":"الظرفية","fr":"locatif"},"cells":["(на) одному","(на) двох","(на) п'яти / п'ятьох"]}]}],"examples":[{"uk":"Я розмовляв з двома студентами і трьома викладачами.","ru":"Я разговаривал с двумя студентами и тремя преподавателями.","en":"I spoke with two students and three teachers.","de":"Ich sprach mit zwei Studenten und drei Dozenten.","it":"Ho parlato con due studenti e tre docenti.","es_ar":"تحدّثت مع طالبَين وثلاثة أساتذة.","fr":"J'ai parlé avec deux étudiants et trois enseignants."},{"uk":"Книга коштує двадцять п'ять гривень; я віддав двадцяти п'яти гривням належне.","ru":"Книга стоит двадцать пять гривен.","en":"The book costs twenty-five hryvnias.","de":"Das Buch kostet fünfundzwanzig Hrywnja.","it":"Il libro costa venticinque grivnie.","es_ar":"يكلّف الكتاب خمسًا وعشرين هريفنا.","fr":"Le livre coûte vingt-cinq hryvnias."},{"uk":"Ми зустрілися двадцять п'ятого травня о сьомій годині.","ru":"Мы встретились двадцать пятого мая в семь часов.","en":"We met on the twenty-fifth of May at seven o'clock.","de":"Wir trafen uns am fünfundzwanzigsten Mai um sieben Uhr.","it":"Ci siamo incontrati il venticinque maggio alle sette.","es_ar":"التقينا في الخامس والعشرين من مايو في الساعة السابعة.","fr":"Nous nous sommes rencontrés le vingt-cinq mai à sept heures."}],"hints":{"ru":"В составных количественных склоняйте КАЖДОЕ слово (з двадцяти п'яти гривень), а в порядковых — только последнее (двадцять п'ятого травня). «Два/три/чотири» имеют формы двох/трьох/чотирьох во всех косвенных падежах. «Сорок, дев'яносто, сто» дают сорока, дев'яноста, ста. У «п'ять»+ часто два варианта: п'яти и п'ятьох.","en":"In compound cardinals decline EVERY word (з двадцяти п'яти гривень), but in ordinals only the last (двадцять п'ятого травня). «Два/три/чотири» use двох/трьох/чотирьох in all oblique cases. «Сорок, дев'яносто, сто» become сорока, дев'яноста, ста. From «п'ять» up, two variants often coexist: п'яти and п'ятьох.","de":"Bei zusammengesetzten Grundzahlen deklinieren Sie JEDES Wort (з двадцяти п'яти гривень), bei Ordnungszahlen nur das letzte (двадцять п'ятого травня). «Два/три/чотири» haben двох/трьох/чотирьох in allen obliquen Kasus. «Сорок, дев'яносто, сто» werden сорока, дев'яноста, ста. Ab «п'ять» gibt es oft zwei Varianten: п'яти und п'ятьох.","it":"Nei cardinali composti declina OGNI parola (з двадцяти п'яти гривень), ma negli ordinali solo l'ultima (двадцять п'ятого травня). «Два/три/чотири» usano двох/трьох/чотирьох in tutti i casi obliqui. «Сорок, дев'яносто, сто» diventano сорока, дев'яноста, ста. Da «п'ять» in su spesso coesistono due varianti: п'яти e п'ятьох.","es_ar":"في الأعداد المركّبة صرِّف كلّ كلمة (з двадцяти п'яти гривень)، أمّا في الترتيبية فالأخيرة فقط (двадцять п'ятого травня). و«два/три/чотири» تستعمل двох/трьох/чотирьох في كلّ الحالات غير المرفوعة. و«сорок، дев'яносто، сто» تصير сорока، дев'яноста، ста. ومن «п'ять» فصاعدًا كثيرًا ما يتعايش شكلان: п'яти و п'ятьох.","fr":"Dans les cardinaux composés, déclinez CHAQUE mot (з двадцяти п'яти гривень), mais dans les ordinaux seul le dernier (двадцять п'ятого травня). «Два/три/чотири» emploient двох/трьох/чотирьох à tous les cas obliques. «Сорок, дев'яносто, сто» deviennent сорока, дев'яноста, ста. À partir de «п'ять», deux variantes coexistent souvent : п'яти et п'ятьох."}}
];
